**4. HTML美化代码**
```html
<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <title>神魔群聊 - Root管理端</title>
    <style>
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
            background: #121212;
            color: #e0e0e0;
            padding: 10px;
        }
        .admin-dashboard {
            max-width: 900px;
            margin: 0 auto;
            background: #1e1e1e;
            border-radius: 12px;
            border: 1px solid #333;
            display: grid;
            grid-template-columns: 2fr 1fr;
            grid-template-rows: auto 1fr;
            gap: 15px;
            padding: 20px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
        }
        .header {
            grid-column: 1 / -1;
            display: flex;
            justify-content: space-between;
            align-items: center;
            border-bottom: 2px solid #00ffcc;
            padding-bottom: 10px;
            margin-bottom: 5px;
        }
        .title { font-size: 20px; font-weight: bold; color: #00ffcc; display: flex; align-items: center; gap: 8px;}
        .root-badge { background: #ff3366; color: white; font-size: 12px; padding: 2px 6px; border-radius: 4px; }

        /* 模块通用样式 */
        .panel { background: #252526; border-radius: 8px; padding: 15px; border: 1px solid #333; }
        .panel-title { font-size: 14px; color: #888; margin-bottom: 10px; text-transform: uppercase; letter-spacing: 1px;}

        /* 公告与活动区 */
        .top-left { display: flex; flex-direction: column; gap: 15px; }
        .announcement { background: rgba(0, 255, 204, 0.1); border-left: 3px solid #00ffcc; padding: 10px; font-size: 14px; line-height: 1.5;}

        .event-details { font-size: 13px; }
        .event-name { font-weight: bold; color: #ffcc00; font-size: 16px; margin-bottom: 5px;}
        .rank-list { margin-top: 10px; display: grid; gap: 5px;}
        .rank-item { display: flex; justify-content: space-between; background: #2d2d30; padding: 5px 10px; border-radius: 4px;}

        /* 聊天记录区 */
        .chat-history { height: 400px; overflow-y: auto; display: flex; flex-direction: column; gap: 10px; padding-right: 5px;}
        /* 滚动条美化 */
        .chat-history::-webkit-scrollbar { width: 6px; }
        .chat-history::-webkit-scrollbar-thumb { background: #555; border-radius: 3px; }

        .msg-box { background: #2d2d30; padding: 10px; border-radius: 8px; font-size: 14px;}
        .msg-header { display: flex; justify-content: space-between; margin-bottom: 5px; font-size: 12px; color: #888;}
        .msg-author { font-weight: bold; color: #fff;}
        .msg-content { color: #ccc; margin-bottom: 8px; line-height: 1.4;}
        .msg-actions { display: flex; gap: 10px; font-size: 12px;}
        .action-btn { background: #3e3e42; border: none; color: #ccc; padding: 3px 8px; border-radius: 4px; cursor: pointer; transition: background 0.2s;}
        .action-btn:hover { background: #555; }

        /* 右侧管理区 */
        .right-sidebar { display: flex; flex-direction: column; gap: 15px; }

        .inventory-list { display: flex; flex-direction: column; gap: 8px;}
        .inv-item { display: flex; justify-content: space-between; align-items: center; background: #2d2d30; padding: 8px; border-radius: 4px; font-size: 13px;}
        .inv-count { color: #00ffcc; font-weight: bold;}

        .member-list { display: flex; flex-direction: column; gap: 8px; max-height: 250px; overflow-y: auto;}
        .member-list::-webkit-scrollbar { width: 4px; }
        .member-list::-webkit-scrollbar-thumb { background: #555; }
        .member-item { background: #2d2d30; padding: 8px; border-radius: 4px; display: flex; flex-direction: column; gap: 5px; font-size: 13px;}
        .mem-header { display: flex; justify-content: space-between; align-items: center;}
        .mem-name { font-weight: bold; cursor: pointer; color: #fff;}
        .mem-name:hover { text-decoration: underline; }
        .status-normal { color: #4caf50; font-size: 11px;}
        .status-banned { color: #ff5252; font-size: 11px;}
        .mem-points { color: #ffcc00; font-size: 11px;}
        .mem-controls { display: flex; gap: 5px;}

    </style>
</head>
<body>
    <div class="admin-dashboard" id="content">
        <div style="text-align:center; padding: 20px; color: #888; width: 100%; grid-column: 1/-1;">正在加载 Root 权限数据...</div>
    </div>

    <script>
        const exampleXML = `<group_chat_admin>$1</group_chat_admin>`;

        function parseXML(xmlText) {
            console.log("解析数据开始...");
            const data = {
                system: { notice: "暂无公告" },
                event: { name: "", rules: "", members: [], ranks: [] },
                messages: [],
                inventory: [],
                members: []
            };

            try {
                // 解析系统公告
                const sysMatch = xmlText.match(/<system_info>([\s\S]*?)<\/system_info>/i);
                if (sysMatch) {
                    const noticeMatch = sysMatch[1].match(/\[群公告\|([^\]]+)\]/);
                    if (noticeMatch) data.system.notice = noticeMatch[1];
                }

                // 解析当前活动
                const evtMatch = xmlText.match(/<current_event>([\s\S]*?)<\/current_event>/i);
                if (evtMatch) {
                    const text = evtMatch[1];
                    const nameMatch = text.match(/\[活动名称\|([^\]]+)\]/);
                    if (nameMatch) data.event.name = nameMatch[1];

                    const ruleMatch = text.match(/\[活动规则\|([^\]]+)\]/);
                    if (ruleMatch) data.event.rules = ruleMatch[1];

                    const partMatch = text.match(/\[参与成员\|([^\]]+)\]/);
                    if (partMatch && !partMatch[1].includes('无')) {
                        data.event.members = partMatch[1].split('|');
                    }

                    const rankMatch = text.match(/\[实时排名\|([^\]]+)\]/);
                    if (rankMatch && !rankMatch[1].includes('无')) {
                        const pairs = rankMatch[1].split('|');
                        pairs.forEach(p => {
                            const [k, v] = p.split(':');
                            if(k && v) data.event.ranks.push({name: k, score: v});
                        });
                    }
                }

                // 解析消息
                const msgMatch = xmlText.match(/<messages>([\s\S]*?)<\/messages>/i);
                if (msgMatch) {
                    const regex = /\[消息\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g;
                    let m;
                    while ((m = regex.exec(msgMatch[1])) !== null) {
                        data.messages.push({ id: m[1], author: m[2], content: m[3], up: m[4], down: m[5], time: m[6] });
                    }
                }

                // 解析库存
                const invMatch = xmlText.match(/<admin_inventory>([\s\S]*?)<\/admin_inventory>/i);
                if (invMatch) {
                    const regex = /\[道具\|([^\|]+)\|([^\]]+)\]/g;
                    let m;
                    while ((m = regex.exec(invMatch[1])) !== null) {
                        if(m[1] !== '无') data.inventory.push({ name: m[1], count: m[2] });
                    }
                }

                // 解析成员
                const memMatch = xmlText.match(/<members>([\s\S]*?)<\/members>/i);
                if (memMatch) {
                    const regex = /\[成员\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g;
                    let m;
                    while ((m = regex.exec(memMatch[1])) !== null) {
                        if(m[1] !== '无') data.members.push({ name: m[1], status: m[2], points: m[3] });
                    }
                }

            } catch (e) { console.error("解析错误", e); }
            return data;
        }

        function render(data) {
            let html = `
                <div class="header">
                    <div class="title">💠 灵犀互联 <span class="root-badge">ROOT</span></div>
                    <div style="font-size: 12px; color: #888;">System Time: ${new Date().toLocaleTimeString()}</div>
                </div>

                <div class="top-left">
                    <div class="panel">
                        <div class="panel-title">📢 群公告</div>
                        <div class="announcement">${data.system.notice}</div>
                    </div>
            `;

            // 活动面板
            if(data.event.name && data.event.name !== '无') {
                html += `
                    <div class="panel">
                        <div class="panel-title">🎯 当前活动</div>
                        <div class="event-name">${data.event.name}</div>
                        <div class="event-details">规则: ${data.event.rules}</div>
                        <div class="rank-list">
                `;
                data.event.ranks.forEach((r, idx) => {
                    let medal = idx === 0 ? '🥇' : idx === 1 ? '🥈' : idx === 2 ? '🥉' : '▪️';
                    html += `<div class="rank-item"><span>${medal} ${r.name}</span> <span style="color:#00ffcc">${r.score}分</span></div>`;
                });
                html += `</div></div>`;
            }

            // 聊天记录
            html += `
                    <div class="panel" style="flex-grow: 1; display:flex; flex-direction:column;">
                        <div class="panel-title">💬 实时监控记录</div>
                        <div class="chat-history">
            `;
            if(data.messages.length === 0) {
                html += `<div style="text-align:center; color:#555; margin-top:20px;">暂无新消息</div>`;
            } else {
                data.messages.forEach(msg => {
                    html += `
                        <div class="msg-box">
                            <div class="msg-header">
                                <span class="msg-author" onclick="handleClick('查看成员', '${msg.author}')" style="cursor:pointer">${msg.author}</span>
                                <span>${msg.time} (ID:${msg.id})</span>
                            </div>
                            <div class="msg-content">${msg.content}</div>
                            <div class="msg-actions">
                                <span>❤️ ${msg.up}</span>
                                <span>👎 ${msg.down}</span>
                            </div>
                        </div>
                    `;
                });
            }
            html += `</div></div></div>`;

            // 右侧面板
            html += `
                <div class="right-sidebar">
                    <div class="panel">
                        <div class="panel-title">🎁 权限库存</div>
                        <div class="inventory-list">
            `;
            if(data.inventory.length === 0) {
                html += `<div class="inv-item">空</div>`;
            } else {
                data.inventory.forEach(inv => {
                    html += `
                        <div class="inv-item" onclick="handleClick('奖励道具', '${inv.name}')" style="cursor:pointer">
                            <span>${inv.name}</span>
                            <span class="inv-count">x${inv.count}</span>
                        </div>
                    `;
                });
            }
            html += `</div></div>`;

            // 成员列表
            html += `
                    <div class="panel" style="flex-grow:1; display:flex; flex-direction:column; overflow:hidden;">
                        <div class="panel-title">👥 成员状态监控</div>
                        <div class="member-list">
            `;
            data.members.forEach(mem => {
                let statusClass = mem.status.includes('禁言') ? 'status-banned' : 'status-normal';
                html += `
                    <div class="member-item">
                        <div class="mem-header">
                            <span class="mem-name" onclick="handleClick('私聊', '${mem.name}')">${mem.name}</span>
                            <span class="${statusClass}">[${mem.status}]</span>
                        </div>
                        <div class="mem-points">功德点: ${mem.points}</div>
                        <div class="mem-controls">
                            <button class="action-btn" onclick="handleClick('操作成员', '禁言 ${mem.name}')">禁言</button>
                            <button class="action-btn" onclick="handleClick('操作成员', '奖励 ${mem.name}')">奖励</button>
                        </div>
                    </div>
                `;
            });
            html += `</div></div></div>`;

            document.getElementById('content').innerHTML = html;
        }

        function handleClick(action, param) {
            if (typeof triggerSlash === 'function') {
                triggerSlash(`/send ${action}：${param}|/trigger`);
            } else {
                alert(`触发指令：${action}：${param}`);
            }
        }

        document.addEventListener('DOMContentLoaded', () => {
            try {
                const data = parseXML(exampleXML);
                render(data);
            } catch(e) {
                document.getElementById('content').innerHTML = "渲染失败: " + e.message;
            }
        });
    </script>
</body>
</html>
```

