    <div class="phone-container" id="content">
        <div style="text-align:center; padding: 20px;">加载中...</div>
    </div>

    <!-- 弹窗容器 -->
    <div class="overlay" id="overlay" onclick="closePopup(event)">
        <div class="popup-panel" id="popup-panel">
            <div class="popup-header">
                <span id="popup-title">标题</span>
