        <div style="text-align:center; padding: 20px;">加载中...</div>
    </div>

    <!-- 弹窗容器 -->
    <div class="overlay" id="overlay" onclick="closePopup(event)">
        <div class="popup-panel" id="popup-panel">
            <div class="popup-header">
                <span id="popup-title">标题</span>
                <span class="close-btn" onclick="closePopup()">✕</span>
            </div>
            <div class="popup-content" id="popup-body"></div>
        </div>
    </div>

    <script>
        const exampleXML = `<group_chat_admin>$1</group_chat_admin>`;
        let globalData = null;

        function parseXML(xmlText) {
            const data = {
                system: { notice: "暂无公告" },
                event: { name: "", rules: "", type: "普通", ranks: [] },
                messages: [], inventory: [], members: []
            };

            try {
                const sysMatch = xmlText.match(/<system_info>([\s\S]*?)<\/system_info>/i);
                if (sysMatch) {
                    const noticeMatch = sysMatch[1].match(/\[群公告\|([^\]]+)\]/);
                    if (noticeMatch) data.system.notice = noticeMatch[1];
                }

                const evtMatch = xmlText.match(/<current_event>([\s\S]*?)<\/current_event>/i);
                if (evtMatch) {
                    const text = evtMatch[1];
                    const nameMatch = text.match(/\[活动名称\|([^\]]+)\]/);
                    if (nameMatch) data.event.name = nameMatch[1];
                    const ruleMatch = text.match(/\[活动规则\|([^\]]+)\]/);
                    if (ruleMatch) data.event.rules = ruleMatch[1];
                    const typeMatch = text.match(/\[活动类型\|([^\]]+)\]/);
                    if (typeMatch) data.event.type = typeMatch[1];

                    const rankMatch = text.match(/\[实时排名\|([^\]]+)\]/);
                    if (rankMatch && !rankMatch[1].includes('无')) {
                        const pairs = rankMatch[1].split('|');
                        pairs.forEach(p => {
                            const [k, v] = p.split(':');
                            if(k && v) data.event.ranks.push({name: k, score: v});
                        });
                    }
                }

                const msgMatch = xmlText.match(/<messages>([\s\S]*?)<\/messages>/i);
                if (msgMatch) {
                    const regex = /\[消息\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g;
                    let m;
                    while ((m = regex.exec(msgMatch[1])) !== null) {
                        data.messages.push({ id: m[1], author: m[2], content: m[3], up: m[4], down: m[5], time: m[6] });
                    }
                }

                const invMatch = xmlText.match(/<admin_inventory>([\s\S]*?)<\/admin_inventory>/i);
                if (invMatch) {
                    const regex = /\[道具\|([^\|]+)\|([^\]]+)\]/g;
                    let m;
                    while ((m = regex.exec(invMatch[1])) !== null) {
                        if(m[1] !== '无') data.inventory.push({ name: m[1], count: m[2] });
                    }
                }

                const memMatch = xmlText.match(/<members>([\s\S]*?)<\/members>/i);
                if (memMatch) {
                    const regex = /\[成员\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g;
                    let m;
                    while ((m = regex.exec(memMatch[1])) !== null) {
                        if(m[1] !== '无') data.members.push({ name: m[1], status: m[2], points: m[3] });
                    }
                }
            } catch (e) { console.error(e); }
            return data;
        }

        function getAvatarColor(name) {
            const colors = ['#f44336', '#e91e63', '#9c27b0', '#3f51b5', '#009688', '#ff9800', '#795548'];
            let hash = 0;
            for(let i = 0; i < name.length; i++) hash = name.charCodeAt(i) + ((hash << 5) - hash);
            return colors[Math.abs(hash) % colors.length];
        }

        function render(data) {
            globalData = data;

            // 1. 顶部栏 (简化)
            let html = `
                <div class="top-bar">
                    <div class="group-title">💠 东西方女神交流群 (${data.members.length > 0 ? data.members.length : '...'})</div>
                </div>
            `;

            // 2. 置顶卡片
            html += `<div class="pinned-area">
                <div><span class="notice-tag">📢 公告:</span> ${data.system.notice}</div>
            `;
            if(data.event.name && data.event.name !== '无') {
                const isVote = data.event.type === '投票';
                html += `
                    <div class="event-card">
                        <div class="event-title">🎯 ${data.event.name}</div>
                        <div class="rank-list">
                `;
                data.event.ranks.forEach(r => {
                    let voteBtn = isVote ? `<button class="vote-mini-btn" onclick="handleClick('投票给', '${r.name}')">投票</button>` : '';
                    html += `<div class="rank-badge">${r.name}: ${r.score} ${voteBtn}</div>`;
                });
                html += `</div></div>`;
            }
            html += `</div>`;

            // 3. 聊天记录
            html += `<div class="chat-area" id="chat-area">`;
            data.messages.forEach(msg => {
                let initial = msg.author.charAt(0);
                let bgColor = getAvatarColor(msg.author);
                html += `
                    <div class="message-row">
                        <div class="avatar" style="background:${bgColor}">${initial}</div>
                        <div class="msg-content-wrapper">
                            <div class="msg-name">${msg.author}</div>
                            <div class="msg-bubble" onclick="handleClick('拍一拍', '${msg.author}')">${msg.content}</div>
                            <div class="msg-meta">
                                <span>${msg.time}</span>
                                <span>❤️ ${msg.up} | 👎 ${msg.down}</span>
                            </div>
                        </div>
                    </div>
                `;
            });
            html += `</div>`;

            // 4. 底部工具栏与输入框 (所有按键横向排列)
            html += `
                <div class="bottom-area">
                    <div class="toolbar">
                        <div class="tool-btn" onclick="openMembers()">👥 群员管理</div>
                        <div class="tool-btn" onclick="openInventory()">🎁 道具库存</div>
                        <div class="tool-btn" onclick="handleClick('群主发红包', '拼手气红包')">🧧 发红包</div>
                        <div class="tool-btn" onclick="handleClick('发起新活动', '开启新游戏')">📝 发活动</div>
                    </div>
                    <div class="input-bar">
                        <div class="fake-input" onclick="alert('提示：请直接在SillyTavern的输入框中打字回复哦~')">作为群主发送消息...</div>
                    </div>
                </div>
            `;

            document.getElementById('content').innerHTML = html;

            setTimeout(() => {
                const chatArea = document.getElementById('chat-area');
                if(chatArea) chatArea.scrollTop = chatArea.scrollHeight;
            }, 100);
        }

        // --- 弹窗逻辑 ---
        function openMembers() {
            document.getElementById('popup-title').innerText = "群成员管理";
            let html = '';
            globalData.members.forEach(mem => {
                let statusStr = mem.status.includes('禁言') ? `<span style="color:#ff4d4f">[禁言中]</span>` : `<span style="color:#4caf50">[正常]</span>`;
                html += `
                    <div class="list-item">
                        <div>
                            <div style="font-weight:bold; font-size:13px;">${mem.name} ${statusStr}</div>
                            <div style="font-size:11px; color:#888;">功德点: ${mem.points}</div>
                        </div>
                        <button class="list-item-btn" onclick="handleClick('系统惩罚', '禁言 ${mem.name}')">禁言套餐</button>
                    </div>
                `;
            });
            document.getElementById('popup-body').innerHTML = html;
            document.getElementById('overlay').style.display = 'flex';
        }

        function openInventory() {
            document.getElementById('popup-title').innerText = "系统道具库存";
            let html = '';
            globalData.inventory.forEach(inv => {
                html += `
                    <div class="list-item">
                        <div>
                            <div style="font-weight:bold; font-size:13px;">${inv.name}</div>
                            <div style="font-size:11px; color:#888;">剩余数量: x${inv.count}</div>
                        </div>
                        <button class="list-item-btn" style="background:#1890ff;" onclick="handleClick('打赏道具', '${inv.name}')">发放奖励</button>
                    </div>
                `;
            });
            if(globalData.inventory.length === 0) html = "<div style='text-align:center;color:#999;padding:20px;font-size:13px;'>库存为空</div>";
            document.getElementById('popup-body').innerHTML = html;
            document.getElementById('overlay').style.display = 'flex';
        }

        function closePopup(e) {
            if (e && e.target !== document.getElementById('overlay') && !e.target.classList.contains('close-btn')) return;
            document.getElementById('overlay').style.display = 'none';
        }

        function handleClick(action, param) {
            if (typeof triggerSlash === 'function') {
                triggerSlash(`/send ${action}：${param}|/trigger`);
            } else {
                alert(`模拟发送：${action}：${param}`);
            }
            closePopup();
        }

        document.addEventListener('DOMContentLoaded', () => {
            render(parseXML(exampleXML));
        });
    </script>
</body>
</html>
```

