    <script>
        const exampleXML = `<group_chat_admin>$1</group_chat_admin>`;
        let globalData = null;

        function getAvatarColor(name) {
            const colors = ['#f44336', '#e91e63', '#9c27b0', '#3f51b5', '#009688', '#ff9800', '#795548'];
            let hash = 0;
            for(let i = 0; i < name.length; i++) hash = name.charCodeAt(i) + ((hash << 5) - hash);
            return colors[Math.abs(hash) % colors.length];
        }

        function parseXML(xmlText) {
            const data = {
                system: { notice: "暂无公告" },
                event: { name: "", rules: "", type: "普通", ranks: [] },
                messages: [], inventory: [], members: [],
                privateChat: { targetName: "无", status: "正常", pmList: [] }
            };

            try {
                // ...解析基础群聊数据...
                const sysMatch = xmlText.match(/<system_info>([\s\S]*?)<\/system_info>/i);
                if (sysMatch) {
                    const noticeMatch = sysMatch[1].match(/\[群公告\|([^\]]+)\]/);
                    if (noticeMatch) data.system.notice = noticeMatch[1];
                }

                const msgMatch = xmlText.match(/<messages>([\s\S]*?)<\/messages>/i);
                if (msgMatch) {
                    const regex = /\[消息\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g;
                    let m; while ((m = regex.exec(msgMatch[1])) !== null) {
                        data.messages.push({ author: m[2], content: m[3], up: m[4], down: m[5], time: m[6] });
                    }
                }

                const invMatch = xmlText.match(/<admin_inventory>([\s\S]*?)<\/admin_inventory>/i);
                if (invMatch) {
                    const regex = /\[道具\|([^\|]+)\|([^\]]+)\]/g;
                    let m; while ((m = regex.exec(invMatch[1])) !== null) {
                        if(m[1] !== '无') data.inventory.push({ name: m[1], count: m[2] });
                    }
                }

                const memMatch = xmlText.match(/<members>([\s\S]*?)<\/members>/i);
                if (memMatch) {
                    const regex = /\[成员\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g;
                    let m; while ((m = regex.exec(memMatch[1])) !== null) {
                        if(m[1] !== '无') data.members.push({ name: m[1], status: m[2], points: m[3] });
                    }
                }

                // === 解析私聊数据 ===
                const pmMatch = xmlText.match(/<private_chat>([\s\S]*?)<\/private_chat>/i);
                if (pmMatch) {
                    const targetMatch = pmMatch[1].match(/\[私聊对象\|([^\]]+)\]/);
                    if (targetMatch) data.privateChat.targetName = targetMatch[1];

                    const stMatch = pmMatch[1].match(/\[对象状态\|([^\]]+)\]/);
                    if (stMatch) data.privateChat.status = stMatch[1];

                    const pmRegex = /\[私聊消息\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g;
                    let m; while ((m = pmRegex.exec(pmMatch[1])) !== null) {
                        data.privateChat.pmList.push({ sender: m[1], content: m[2], time: m[3] });
                    }
                }
            } catch (e) { console.error(e); }
            return data;
        }

        function render(data) {
            globalData = data;
            document.getElementById('member-count').innerText = data.members.length;
            document.getElementById('pinned-area').innerHTML = `<div><span class="notice-tag">📢 公告:</span> ${data.system.notice}</div>`;

            // 渲染群聊
            let chatHtml = '';
            data.messages.forEach(msg => {
                let initial = msg.author.charAt(0);
                let bgColor = getAvatarColor(msg.author);
                chatHtml += `
                    <div class="message-row">
                        <div class="avatar" style="background:${bgColor}">${initial}</div>
                        <div class="msg-content-wrapper">
                            <div class="msg-name">${msg.author}</div>
                            <div class="msg-bubble" onclick="handleClick('拍一拍', '${msg.author}')">${msg.content}</div>
                        </div>
                    </div>
                `;
            });
            document.getElementById('chat-area').innerHTML = chatHtml;

            // ===== 自动判定是否展开私聊抽屉 =====
            if (data.privateChat.targetName !== '无') {
                renderPrivateDrawer(data.privateChat);
                document.getElementById('private-drawer').classList.add('open');
            } else {
                document.getElementById('private-drawer').classList.remove('open');
            }

            setTimeout(() => {
                const chatArea = document.getElementById('chat-area');
                if(chatArea) chatArea.scrollTop = chatArea.scrollHeight;
                const pmArea = document.getElementById('drawer-chat');
                if(pmArea) pmArea.scrollTop = pmArea.scrollHeight;
            }, 100);
        }

        function renderPrivateDrawer(pmData) {
            let statusClass = pmData.status.includes('禁言') ? 'status-banned' : 'status-normal';
            document.getElementById('drawer-title').innerHTML = `${pmData.targetName} <span class="status-badge ${statusClass}">${pmData.status}</span>`;

            let pmHtml = '';
            let targetColor = getAvatarColor(pmData.targetName);
            let targetInitial = pmData.targetName.charAt(0);

            pmData.pmList.forEach(msg => {
                if (msg.sender === '群主') {
                    pmHtml += `
                        <div class="pm-row pm-right">
                            <div class="avatar" style="background:#333">R</div>
                            <div class="msg-content-wrapper"><div class="pm-bubble">${msg.content}</div></div>
                        </div>`;
                } else {
                    pmHtml += `
                        <div class="pm-row pm-left">
                            <div class="avatar" style="background:${targetColor}">${targetInitial}</div>
                            <div class="msg-content-wrapper"><div class="pm-bubble">${msg.content}</div></div>
                        </div>`;
                }
            });
            if(pmData.pmList.length === 0) pmHtml = `<div style="text-align:center; color:#999; font-size:11px;">暂无私聊记录</div>`;
            document.getElementById('drawer-chat').innerHTML = pmHtml;
        }

        // --- 抽屉操作与弹窗 ---
        function closePrivateDrawer() {
            // 只关闭界面显示，不发送任何后台指令！
            document.getElementById('private-drawer').classList.remove('open');
        }

        function openMembers() {
            document.getElementById('popup-title').innerText = "群成员管理";
            let html = '';
            globalData.members.forEach(mem => {
                html += `
                    <div class="list-item">
                        <div style="font-size:13px; font-weight:bold;">${mem.name}</div>
                        <button class="list-item-btn blue" onclick="handleClick('查看私聊', '${mem.name}')">看私聊</button>
                    </div>
                `;
            });
            document.getElementById('popup-body').innerHTML = html;
            document.getElementById('overlay').style.display = 'flex';
        }

        function openInventory() { /* 与之前类似，省略详细实现 */ }

        function closePopup(e) {
            if (e && e.target !== document.getElementById('overlay') && !e.target.classList.contains('close-btn')) return;
            document.getElementById('overlay').style.display = 'none';
        }

        // --- 联动发送逻辑 ---
        function handleClick(action, param) {
            if (typeof triggerSlash === 'function') {
                triggerSlash(`/send ${action}：${param}|/trigger`);
            } else {
                alert(`模拟发送指令给AI：${action} ${param}`);
            }
            closePopup();
        }

        function triggerOfflineDate() {
            let target = globalData.privateChat.targetName;
            handleClick('使用神念降临协议发起线下约会', target);
        }
        function triggerAction() {
            let target = globalData.privateChat.targetName;
            handleClick('发送互动指令给', target);
        }

        document.addEventListener('DOMContentLoaded', () => {
            render(parseXML(exampleXML));
        });
    </script>
</body>
</html>
