                        data.messages.push({ author: m[2], content: m[3], up: m[4], down: m[5], time: m[6] });
                    }
                }

                const invMatch = xmlText.match(/<admin_inventory>([\s\S]*?)<\/admin_inventory>/i);
                if (invMatch) {
