    <script>
        const exampleXML = `<group_chat_admin>$1</group_chat_admin>`;
        let globalData = null;
        let memberStatusMap = {}; // 用于快速查询成员状态 (发光、禁言等)

        function getAvatarColor(name) {
            const colors = ['#f44336', '#e91e63', '#9c27b0', '#3f51b5', '#009688', '#ff9800', '#795548'];
            let hash = 0; for(let i = 0; i < name.length; i++) hash = name.charCodeAt(i) + ((hash << 5) - hash);
            return colors[Math.abs(hash) % colors.length];
        }

        function parseXML(xmlText) {
            const data = {
                system: { notice: "暂无公告" },
                event: { name: "", rules: "", type: "普通", ranks: [] },
                messages: [], inventory: [], members: [],
                privateChat: { targetName: "无", status: "正常", pmList: [] }
            };
            try {
                // ...解析同之前版本，加入安全防护...
                const sysMatch = xmlText.match(/<system_info>([\s\S]*?)<\/system_info>/i);
                if (sysMatch) { const n = sysMatch[1].match(/\[群公告\|([^\]]+)\]/); if(n) data.system.notice = n[1]; }

                const evtMatch = xmlText.match(/<current_event>([\s\S]*?)<\/current_event>/i);
                if (evtMatch) {
                    const t = evtMatch[1];
                    const nMatch = t.match(/\[活动名称\|([^\]]+)\]/); if(nMatch) data.event.name = nMatch[1];
                    const rankMatch = t.match(/\[实时排名\|([^\]]+)\]/);
                    if(rankMatch && !rankMatch[1].includes('无')){
                        rankMatch[1].split('|').forEach(p => { const [k,v] = p.split(':'); if(k&&v) data.event.ranks.push({name:k,score:v}); });
                    }
                }

                const memMatch = xmlText.match(/<members>([\s\S]*?)<\/members>/i);
                if (memMatch) {
                    const regex = /\[成员\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g; let m;
                    while ((m = regex.exec(memMatch[1])) !== null) {
                        if(m[1] !== '无') {
                            data.members.push({ name: m[1], status: m[2], points: m[3] });
                            memberStatusMap[m[1]] = m[2]; // 存入映射表供消息气泡查阅
                        }
                    }
                }

                const msgMatch = xmlText.match(/<messages>([\s\S]*?)<\/messages>/i);
                if (msgMatch) {
                    const regex = /\[消息\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g; let m;
                    while ((m = regex.exec(msgMatch[1])) !== null) {
                        data.messages.push({ author: m[2], content: m[3], time: m[6] });
                    }
                }

                const pmMatch = xmlText.match(/<private_chat>([\s\S]*?)<\/private_chat>/i);
                if (pmMatch) {
                    const t = pmMatch[1].match(/\[私聊对象\|([^\]]+)\]/); if(t) data.privateChat.targetName = t[1];
                    const s = pmMatch[1].match(/\[对象状态\|([^\]]+)\]/); if(s) data.privateChat.status = s[1];
                    const pmRegex = /\[私聊消息\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g; let m;
                    while ((m = pmRegex.exec(pmMatch[1])) !== null) {
                        data.privateChat.pmList.push({ sender: m[1], content: m[2], time: m[3] });
                    }
                }
            } catch (e) { console.error(e); }
            return data;
        }

        // ====== 特效系统 ======
        function triggerShake() {
            const container = document.querySelector('.phone-container');
            container.classList.add('shake-effect');
            setTimeout(() => container.classList.remove('shake-effect'), 500);
        }

        function createRedPacketRain() {
            const container = document.querySelector('.phone-container');
            for(let i=0; i<15; i++){
                let rp = document.createElement('div');
                rp.className = 'red-packet';
                rp.innerText = '🧧';
                rp.style.left = Math.random() * 90 + '%';
                rp.style.top = '-30px';
                rp.style.animationDuration = (Math.random() * 1 + 1) + 's';
                rp.style.animationDelay = (Math.random() * 0.5) + 's';
                container.appendChild(rp);
                setTimeout(() => rp.remove(), 2000);
            }
        }

        function render(data) {
            globalData = data;
            let needShake = false;
            let needRain = false;

            // 检查霸屏特效
            data.messages.forEach(msg => {
                if(msg.content.includes('💥') || msg.content.includes('🔥')) needShake = true;
                if(msg.content.includes('🧧')) needRain = true;
            });

            // 渲染HTML结构
            let html = `
                <div class="top-bar">
                    <div class="group-title">💠 神魔跨界终端 (<span id="member-count">${data.members.length}</span>)</div>
                </div>
                <div class="pinned-area">
                    <div><span class="notice-tag">📢 警告:</span> ${data.system.notice}</div>
            `;
            if(data.event.ranks.length > 0){
                html += `<div class="event-card"><div class="event-title">🎯 ${data.event.name || '当前活动'}</div><div class="rank-list">`;
                data.event.ranks.forEach(r => { html += `<div class="rank-badge">${r.name}: ${r.score}</div>`; });
                html += `</div></div>`;
            }
            html += `</div><div class="chat-area" id="chat-area">`;

            // 渲染消息 (注入发光与禁言状态)
            data.messages.forEach(msg => {
                let initial = msg.author.charAt(0);
                let bgColor = getAvatarColor(msg.author);

                // 查询状态
                let status = memberStatusMap[msg.author] || "正常";
                let avatarClass = status.includes("禁言") ? "avatar banned" : "avatar";
                let bubbleClass = status.includes("发光") ? "msg-bubble glow-bubble" : "msg-bubble";

                html += `
                    <div class="message-row">
                        <div class="${avatarClass}" style="background:${status.includes('禁言')?'#555':bgColor}" onclick="handleClick('拍一拍', '${msg.author}')">${initial}</div>
                        <div class="msg-content-wrapper">
                            <div class="msg-name">${msg.author}</div>
                            <div class="${bubbleClass}">${msg.content}</div>
                        </div>
                    </div>
                `;
            });
            html += `</div>`; // chat-area end

            // 底部操作区
            html += `
                <div class="bottom-area">
                    <div class="toolbar">
                        <div class="tool-btn" onclick="openMembers()">👥 群员监控</div>
                        <div class="tool-btn" onclick="handleClick('群主发红包', '拼手气红包')">🧧 撒功德</div>
                        <div class="tool-btn" onclick="handleClick('发起新活动', '开启新游戏')">📝 定规则</div>
                    </div>
                    <div class="input-bar">
                        <div class="fake-input" onclick="alert('输入指令...')">以[群主]身份发布神谕...</div>
                    </div>
                </div>
            `;

            // 弹窗
            html += `
                <div class="overlay" id="overlay" onclick="closePopup(event)">
                    <div class="popup-panel" id="popup-panel">
                        <div class="popup-header"><span id="popup-title">管理面板</span><span class="close-btn" onclick="closePopup()">✕</span></div>
                        <div class="popup-content" id="popup-body"></div>
                    </div>
                </div>
            `;

            // 抽屉私聊 (加入群主挂件)
            html += `
                <div class="private-drawer" id="private-drawer">
                    <div class="drawer-top">
                        <div class="drawer-back" onclick="closePrivateDrawer()">❮ 收起</div>
                        <div class="drawer-title" id="drawer-title">未知</div>
                        <div class="pm-icon">⋯</div>
                    </div>
                    <div class="drawer-chat" id="drawer-chat"></div>
                    <div class="drawer-bottom">
                        <div class="fake-input" onclick="alert('输入私密指令...')">私密传音...</div>
                        <div class="pm-icon" title="线下约会" onclick="handleClick('使用神念降临协议发起线下约会', '${data.privateChat.targetName}')">🏨</div>
                        <div class="pm-icon" title="互动指令" onclick="handleClick('发送互动指令给', '${data.privateChat.targetName}')">⊕</div>
                    </div>
                </div>
            `;

            document.getElementById('content').innerHTML = html;

            // 渲染私聊内容
            if (data.privateChat.targetName !== '无') {
                let pmData = data.privateChat;
                let statusClass = pmData.status.includes('禁言') ? 'status-banned' : (pmData.status.includes('发光') ? 'status-glow' : 'status-normal');
                document.getElementById('drawer-title').innerHTML = `${pmData.targetName} <span class="status-badge ${statusClass}">${pmData.status}</span>`;

                let pmHtml = '';
                let targetColor = getAvatarColor(pmData.targetName);
                let targetInitial = pmData.targetName.charAt(0);

                pmData.pmList.forEach(msg => {
                    if (msg.sender === '群主') {
                        // 群主气泡：带王冠
                        pmHtml += `
                            <div class="message-row msg-right" style="margin-bottom:10px;">
                                <div class="avatar" style="background:#222">R</div>
                                <div class="msg-content-wrapper"><div class="msg-bubble">${msg.content}</div></div>
                            </div>`;
                    } else {
                        pmHtml += `
                            <div class="message-row msg-left" style="margin-bottom:10px;">
                                <div class="avatar" style="background:${targetColor}">${targetInitial}</div>
                                <div class="msg-content-wrapper"><div class="pm-bubble">${msg.content}</div></div>
                            </div>`;
                    }
                });
                document.getElementById('drawer-chat').innerHTML = pmHtml;
                document.getElementById('private-drawer').classList.add('open');
            }

            // 滚动与特效触发
            setTimeout(() => {
                const chatArea = document.getElementById('chat-area'); if(chatArea) chatArea.scrollTop = chatArea.scrollHeight;
                const pmArea = document.getElementById('drawer-chat'); if(pmArea) pmArea.scrollTop = pmArea.scrollHeight;
                if(needShake) triggerShake();
                if(needRain) createRedPacketRain();
            }, 100);
        }

        // --- 交互功能 ---
        function openMembers() {
            let html = '';
            globalData.members.forEach(mem => {
                let badge = '';
                if(mem.status.includes('禁言')) badge = `<span class="status-badge status-banned">封印</span>`;
                else if(mem.status.includes('发光')) badge = `<span class="status-badge status-glow">群宠✨</span>`;

                html += `
                    <div class="list-item">
                        <div style="font-size:13px; font-weight:bold;">${mem.name} ${badge}</div>
                        <div class="btn-group">
                            <button class="list-item-btn blue" onclick="handleClick('查看私聊', '${mem.name}')">私联</button>
                            <button class="list-item-btn" onclick="handleClick('系统惩罚', '禁言 ${mem.name}')">禁言</button>
                        </div>
                    </div>
                `;
            });
            document.getElementById('popup-body').innerHTML = html;
            document.getElementById('overlay').style.display = 'flex';
        }
        function closePopup(e) { if (e && e.target !== document.getElementById('overlay') && !e.target.classList.contains('close-btn')) return; document.getElementById('overlay').style.display = 'none'; }
        function closePrivateDrawer() { document.getElementById('private-drawer').classList.remove('open'); }
        function handleClick(action, param) {
            if (typeof triggerSlash === 'function') triggerSlash(`/send ${action}：${param}|/trigger`);
            else alert(`模拟发送指令给AI：${action} ${param}`);
            closePopup();
        }

        document.addEventListener('DOMContentLoaded', () => { render(parseXML(exampleXML)); });
    </script>
</body>
</html>
