            display: flex; align-items: center; gap: 4px; font-size: 12px; color: #fff; cursor: pointer;
            padding: 8px 12px; border-radius: 12px; background: rgba(255,255,255,0.1); border: 1px solid rgba(255,255,255,0.2);
            transition: all 0.2s; backdrop-filter: blur(5px);
        }
        .tool-btn:hover { background: rgba(0, 255, 204, 0.2); border-color: #00ffcc; color: #00ffcc; transform: translateY(-2px);}

        .input-bar { padding: 12px 15px; display: flex; align-items: center; gap: 10px; }
        .real-input {
            flex: 1; height: 40px; background: rgba(255,255,255,0.1); border-radius: 20px;
            padding: 0 15px; color: #fff; font-size: 14px; border: 1px solid rgba(255,255,255,0.2);
            outline: none; transition: all 0.2s;
        }
        .real-input:focus { border-color: #00ffcc; box-shadow: 0 0 10px rgba(0,255,204,0.3); background: rgba(255,255,255,0.15); }
        .real-input::placeholder { color: #888; }

        .send-btn {
            width: 40px; height: 40px; border-radius: 50%; background: #00ffcc; color: #000;
            display: flex; justify-content: center; align-items: center; font-size: 18px; font-weight: bold;
            cursor: pointer; box-shadow: 0 0 10px rgba(0,255,204,0.5); transition: transform 0.2s; border: none; outline: none;
        }
        .send-btn:hover { transform: scale(1.1); box-shadow: 0 0 15px rgba(0,255,204,0.8); }

        .overlay { position: absolute; top: 0; left: 0; right: 0; bottom: 0; background: rgba(0,0,0,0.7); z-index: 50; display: none; justify-content: center; align-items: center; }
        .popup-panel { background: rgba(30, 30, 45, 0.95); width: 90%; max-height: 80%; border-radius: 20px; display: flex; flex-direction: column; border: 1px solid rgba(255,255,255,0.1); box-shadow: 0 20px 50px rgba(0,0,0,0.8); color: #fff; }
        .popup-header { padding: 15px; border-bottom: 1px solid rgba(255,255,255,0.1); display: flex; justify-content: space-between; font-weight: bold; }
        .close-btn { cursor: pointer; color: #888; font-size: 18px;}
        .popup-content { padding: 15px; overflow-y: auto; display: flex; flex-direction: column; gap: 10px;}

        .list-item { display: flex; justify-content: space-between; align-items: center; padding: 10px; background: rgba(0,0,0,0.3); border-radius: 12px;}
        .btn-group { display: flex; gap: 8px; }
        .list-item-btn { background: rgba(255, 51, 102, 0.8); color: white; border: none; padding: 6px 10px; border-radius: 6px; font-size: 12px; cursor: pointer;}
        .list-item-btn.blue { background: rgba(0, 255, 204, 0.8); color: #000; font-weight: bold;}
        .list-item-btn.green { background: rgba(0, 200, 80, 0.8); color: #fff;}

        .action-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }
        .action-btn { background: rgba(255,255,255,0.1); border: 1px solid rgba(255,255,255,0.2); color: #fff; padding: 12px; border-radius: 10px; text-align: center; cursor: pointer; transition: all 0.2s; font-size: 13px;}
        .action-btn:hover { background: rgba(0, 255, 204, 0.2); border-color: #00ffcc; color: #00ffcc; }
        .action-section-title { font-size: 12px; color: #888; margin-top: 10px; margin-bottom: 5px; }

        .private-drawer {
            position: absolute; top: 0; left: 0; right: 0; bottom: 0; background: rgba(20, 20, 30, 0.98); z-index: 40;
            display: flex; flex-direction: column; transform: translateX(100%); transition: transform 0.4s cubic-bezier(0.19, 1, 0.22, 1);
        }
        .private-drawer.open { transform: translateX(0); }
        .drawer-top { background: rgba(0,0,0,0.8); color: #fff; padding: 15px; display: flex; justify-content: space-between; align-items: center; border-bottom: 1px solid rgba(255,255,255,0.1); }
        .drawer-back { font-size: 16px; cursor: pointer; color: #00ffcc; display: flex; align-items: center; }
        .drawer-title { font-size: 16px; font-weight: bold; }
        .drawer-chat { flex: 1; padding: 15px; overflow-y: auto; display: flex; flex-direction: column; gap: 15px; }
        .pm-bubble { padding: 10px 14px; font-size: 15px; line-height: 1.4; border-radius: 4px 16px 16px 16px; background: #fff; color: #111;}
        .pm-right .pm-bubble { border-radius: 16px 4px 16px 16px; background: #00ffcc; color: #000;}
        .drawer-bottom { background: rgba(0,0,0,0.8); border-top: 1px solid rgba(255,255,255,0.1); padding: 12px 15px; display: flex; align-items: center; gap: 12px; }
        .pm-icon { font-size: 24px; cursor: pointer; color: #00ffcc; transition: transform 0.2s; display: flex; justify-content: center; align-items: center; width: 36px; height: 36px; border-radius: 50%; background: rgba(255,255,255,0.1);}
        .pm-icon:hover { transform: scale(1.1); background: rgba(0,255,204,0.2); }

        .status-badge { font-size: 10px; padding: 2px 6px; border-radius: 6px; margin-left: 5px; font-weight: bold; }
        .status-normal { background: rgba(0, 255, 204, 0.2); color: #00ffcc; }
        .status-banned { background: rgba(255, 51, 102, 0.2); color: #ff3366; border: 1px solid #ff3366;}
        .status-glow { background: rgba(255, 215, 0, 0.2); color: #ffd700; border: 1px solid #ffd700;}
    </style>
</head>
<body>
    <div class="phone-container" id="content"></div>

    <script>
        const exampleXML = `<group_chat_admin>$1</group_chat_admin>`;
        let globalData = null;
        let memberStatusMap = {};

        function getAvatarColor(name) {
            const colors = ['#f44336', '#e91e63', '#9c27b0', '#3f51b5', '#009688', '#ff9800', '#795548'];
            let hash = 0; for(let i = 0; i < name.length; i++) hash = name.charCodeAt(i) + ((hash << 5) - hash);
            return colors[Math.abs(hash) % colors.length];
        }

        function parseXML(xmlText) {
            const data = {
                system: { notice: "暂无公告" }, event: { name: "", rules: "", type: "普通", ranks: [] },
                messages: [], inventory: [], members: [], privateChat: { targetName: "无", status: "正常", pmList: [] }
            };
            try {
                const sysMatch = xmlText.match(/<system_info>([\s\S]*?)<\/system_info>/i);
                if (sysMatch) { const n = sysMatch[1].match(/\[群公告\|([^\]]+)\]/); if(n) data.system.notice = n[1]; }
                const evtMatch = xmlText.match(/<current_event>([\s\S]*?)<\/current_event>/i);
                if (evtMatch) {
                    const t = evtMatch[1];
                    const nMatch = t.match(/\[活动名称\|([^\]]+)\]/); if(nMatch) data.event.name = nMatch[1];
                    const rMatch = t.match(/\[活动规则\|([^\]]+)\]/); if(rMatch) data.event.rules = rMatch[1];
                    const rankMatch = t.match(/\[实时排名\|([^\]]+)\]/);
                    if(rankMatch && !rankMatch[1].includes('无')){ rankMatch[1].split('|').forEach(p => { const [k,v] = p.split(':'); if(k&&v) data.event.ranks.push({name:k,score:v}); }); }
                }
                const invMatch = xmlText.match(/<admin_inventory>([\s\S]*?)<\/admin_inventory>/i);
                if (invMatch) {
                    const regex = /\[道具\|([^\|]+)\|([^\]]+)\]/g; let m;
                    while ((m = regex.exec(invMatch[1])) !== null) { if(m[1] !== '无') data.inventory.push({ name: m[1], count: m[2] }); }
                }
                const memMatch = xmlText.match(/<members>([\s\S]*?)<\/members>/i);
                if (memMatch) {
                    const regex = /\[成员\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g; let m;
                    while ((m = regex.exec(memMatch[1])) !== null) {
                        if(m[1] !== '无') { data.members.push({ name: m[1], status: m[2], points: m[3] }); memberStatusMap[m[1]] = m[2]; }
                    }
                }
                const msgMatch = xmlText.match(/<messages>([\s\S]*?)<\/messages>/i);
                if (msgMatch) {
                    const regex = /\[消息\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g; let m;
                    while ((m = regex.exec(msgMatch[1])) !== null) { data.messages.push({ author: m[2], content: m[3], time: m[6] }); }
                }
                const pmMatch = xmlText.match(/<private_chat>([\s\S]*?)<\/private_chat>/i);
                if (pmMatch) {
                    const t = pmMatch[1].match(/\[私聊对象\|([^\]]+)\]/); if(t) data.privateChat.targetName = t[1];
                    const s = pmMatch[1].match(/\[对象状态\|([^\]]+)\]/); if(s) data.privateChat.status = s[1];
                    const pmRegex = /\[私聊消息\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g; let m;
                    while ((m = pmRegex.exec(pmMatch[1])) !== null) { data.privateChat.pmList.push({ sender: m[1], content: m[2], time: m[3] }); }
                }
            } catch (e) { console.error(e); }
            return data;
        }

        function triggerShake() {
            const container = document.querySelector('.phone-container');
            container.classList.add('shake-effect'); setTimeout(() => container.classList.remove('shake-effect'), 500);
        }

        function createRedPacketRain() {
            const container = document.querySelector('.phone-container');
            for(let i=0; i<15; i++){
                let rp = document.createElement('div'); rp.className = 'red-packet'; rp.innerText = '🧧';
                rp.style.left = Math.random() * 90 + '%'; rp.style.top = '-30px';
                rp.style.animationDuration = (Math.random() * 1 + 1) + 's'; rp.style.animationDelay = (Math.random() * 0.5) + 's';
                container.appendChild(rp); setTimeout(() => rp.remove(), 2000);
            }
        }

        function sendActualMessage(inputId) {
            const inputEl = document.getElementById(inputId);
            if(!inputEl) return;
            const text = inputEl.value.trim();
            if(!text) return;

            try {
                const stTextarea = document.getElementById('send_textarea');
                const stSendBtn = document.getElementById('send_but');
                if (stTextarea && stSendBtn) {
                    stTextarea.value = text;
                    stTextarea.dispatchEvent(new Event('input', { bubbles: true }));
                    stSendBtn.click();
                    inputEl.value = '';
                    return;
                }
            } catch(e) { console.log(e); }

            if (typeof triggerSlash === 'function') {
                triggerSlash(text);
                inputEl.value = '';
            } else {
                alert(`模拟发送：${text}`);
            }
        }

        function handleEnterKey(event, inputId) {
            if (event.key === 'Enter') { event.preventDefault(); sendActualMessage(inputId); }
        }

        function render(data) {
            globalData = data;
            let needShake = false; let needRain = false;
            data.messages.forEach(msg => {
                if(msg.content.includes('💥') || msg.content.includes('🔥')) needShake = true;
                if(msg.content.includes('🧧')) needRain = true;
            });

            let html = `
                <div class="top-bar"><div class="group-title">💠 神魔跨界终端 (${data.members.length})</div></div>
                <div class="pinned-area"><div><span class="notice-tag">📢 警告:</span> ${data.system.notice}</div>
            `;
            // 活动区域渲染
            if(data.event.ranks.length > 0 || data.event.name !== "无"){
                html += `
                <div class="event-card">
                    <div class="event-title">🎯 ${data.event.name || '当前活动'}</div>
                    <div class="event-rules">规则: ${data.event.rules || '无'}</div>
                    <div class="rank-list">`;
                data.event.ranks.forEach(r => { html += `<div class="rank-badge">${r.name}: ${r.score}票</div>`; });
                html += `</div></div>`;
            }
            html += `</div><div class="chat-area" id="chat-area">`;

            data.messages.forEach(msg => {
                let initial = msg.author.charAt(0); let bgColor = getAvatarColor(msg.author);
                let status = memberStatusMap[msg.author] || "正常";
                let avatarClass = status.includes("禁言") ? "avatar banned" : "avatar";
                let bubbleClass = status.includes("发光") ? "msg-bubble glow-bubble" : "msg-bubble";

                html += `
                    <div class="message-row">
                        <div class="${avatarClass}" style="background:${status.includes('禁言')?'#555':bgColor}" onclick="handleClick('拍一拍', '${msg.author}')">${initial}</div>
                        <div class="msg-content-wrapper">
                            <div class="msg-name">${msg.author}</div>
                            <div class="${bubbleClass}">${msg.content}</div>
                        </div>
                    </div>`;
            });
            html += `</div>`;

            // ===== 重新排版的底部快捷栏 =====
            // 去掉了库存，留下四个最常用的：监控、撒币、赛事管理、更多
            html += `
                <div class="bottom-area">
                    <div class="toolbar">
                        <div class="tool-btn" onclick="openMembers()">👥 监控</div>
                        <div class="tool-btn" onclick="handleClick('群主发红包', '拼手气红包')">🧧 撒币</div>
                        <div class="tool-btn" onclick="openEventCenter()" style="border-color:#00ffcc; color:#00ffcc;">🏆 赛事</div>
                        <div class="tool-btn" onclick="openGroupActions()">⚙️ 更多</div>
                    </div>
                    <div class="input-bar">
                        <input type="text" class="real-input" id="group-real-input" placeholder="作为[群主]发话..." onkeypress="handleEnterKey(event, 'group-real-input')">
                        <button class="send-btn" title="发送" onclick="sendActualMessage('group-real-input')">➤</button>
                    </div>
                </div>
            `;

            // 弹窗
            html += `
                <div class="overlay" id="overlay" onclick="closePopup(event)">
                    <div class="popup-panel" id="popup-panel">
                        <div class="popup-header"><span id="popup-title">管理面板</span><span class="close-btn" onclick="closePopup()">✕</span></div>
                        <div class="popup-content" id="popup-body"></div>
                    </div>
                </div>
            `;

            // 私聊面板
            html += `
                <div class="private-drawer" id="private-drawer">
                    <div class="drawer-top">
                        <div class="drawer-back" onclick="closePrivateDrawer()">❮ 收起</div>
                        <div class="drawer-title" id="drawer-title">未知</div>
                        <div class="pm-icon" onclick="openPrivateActions()" style="font-size: 16px; width:28px; height:28px;">⚙️</div>
                    </div>
                    <div class="drawer-chat" id="drawer-chat"></div>
                    <div class="drawer-bottom">
                        <input type="text" class="real-input" id="pm-real-input" placeholder="私密传音..." onkeypress="handleEnterKey(event, 'pm-real-input')" style="height:36px; font-size:13px;">
                        <button class="send-btn" style="width:36px; height:36px; font-size:14px;" onclick="sendActualMessage('pm-real-input')">➤</button>
                        <div class="pm-icon" title="线下约会" onclick="handleClick('使用神念降临协议发起线下约会', '${data.privateChat.targetName}')">🏨</div>
                    </div>
                </div>
            `;

            document.getElementById('content').innerHTML = html;

            if (data.privateChat.targetName !== '无') {
                let pmData = data.privateChat;
                let statusClass = pmData.status.includes('禁言') ? 'status-banned' : (pmData.status.includes('发光') ? 'status-glow' : 'status-normal');
                document.getElementById('drawer-title').innerHTML = `${pmData.targetName} <span class="status-badge ${statusClass}">${pmData.status}</span>`;
                let pmHtml = ''; let targetColor = getAvatarColor(pmData.targetName); let targetInitial = pmData.targetName.charAt(0);
                pmData.pmList.forEach(msg => {
                    if (msg.sender === '群主') {
                        pmHtml += `<div class="message-row msg-right" style="margin-bottom:10px;"><div class="avatar" style="background:#222">R</div><div class="msg-content-wrapper"><div class="msg-bubble">${msg.content}</div></div></div>`;
                    } else {
                        pmHtml += `<div class="message-row msg-left" style="margin-bottom:10px;"><div class="avatar" style="background:${targetColor}">${targetInitial}</div><div class="msg-content-wrapper"><div class="pm-bubble">${msg.content}</div></div></div>`;
                    }
                });
                document.getElementById('drawer-chat').innerHTML = pmHtml;
                document.getElementById('private-drawer').classList.add('open');
            }

            setTimeout(() => {
                const chatArea = document.getElementById('chat-area'); if(chatArea) chatArea.scrollTop = chatArea.scrollHeight;
                const pmArea = document.getElementById('drawer-chat'); if(pmArea) pmArea.scrollTop = pmArea.scrollHeight;
                if(needShake) triggerShake(); if(needRain) createRedPacketRain();
            }, 100);
        }

        function closePopup(e) { if (e && e.target !== document.getElementById('overlay') && !e.target.classList.contains('close-btn')) return; document.getElementById('overlay').style.display = 'none'; }
        function closePrivateDrawer() { document.getElementById('private-drawer').classList.remove('open'); }
        function handleClick(action, param) {
            if (typeof triggerSlash === 'function') triggerSlash(`/send ${action}：${param}|/trigger`);
            else alert(`模拟发送：${action} ${param}`);
            closePopup();
        }

        function sendCustomEvent() {
            const inputEl = document.getElementById('custom-event-input');
            if (inputEl && inputEl.value.trim()) {
                handleClick('发起新活动', inputEl.value.trim());
                inputEl.value = '';
            }
        }

        function handleCustomEventKey(event) {
            if (event.key === 'Enter') {
                event.preventDefault();
                sendCustomEvent();
            }
        }

        // ================= 升级版：赛事管理中心 =================
        function openEventCenter() {
            document.getElementById('popup-title').innerText = "🏆 赛事管理中心";
            let html = `
                <!-- 新增：自定义赛事输入框 -->
                <div class="action-section-title" style="color:#00ffcc;">✍️ 自定义举办赛事</div>
                <div style="display:flex; gap:10px; margin-bottom:15px;">
                    <input type="text" id="custom-event-input" class="real-input" style="height:36px; font-size:12px; background:rgba(0,0,0,0.5);" placeholder="输入你想举办的任意比赛名称..." onkeypress="handleCustomEventKey(event)">
                    <button class="send-btn" style="width:50px; height:36px; font-size:13px; flex-shrink:0; border-radius:10px;" onclick="sendCustomEvent()">发起</button>
                </div>

                <div class="action-section-title" style="color:#888;">🎯 经典赛事模板</div>
                <div class="action-grid">
                    <div class="action-btn" onclick="handleClick('发起新活动', '诸界泳装选美大赛')">👙 泳装选美</div>
                    <div class="action-btn" onclick="handleClick('发起新活动', '极限撒娇大作战')">🥺 撒娇大作战</div>
                    <div class="action-btn" onclick="handleClick('发起新活动', '厨艺黑暗料理大赛')">🍳 黑暗料理赛</div>
                    <div class="action-btn" onclick="handleClick('发起新活动', '真心话大冒险')">🎲 真心话大冒险</div>
                </div>

                <div class="action-section-title" style="color:#ffd700;">👑 赛事干预与结算</div>
                <div class="action-grid">
                    <div class="action-btn" style="border-color:#ff3366;" onclick="handleClick('赛事管理', '强制全体成员参加当前活动并拉票')">📢 强制拉票</div>
                    <div class="action-btn" style="border-color:#ffd700;" onclick="handleClick('赛事管理', '立刻结算当前活动并根据投票排名公布结果')">✅ 立刻结算</div>
                    <div class="action-btn" style="border-color:#ffd700;" onclick="handleClick('赛事管理', '给票数最高的冠军颁发【免死金牌】')">🥇 颁发免死金牌</div>
                    <div class="action-btn" style="border-color:#ffd700;" onclick="handleClick('赛事管理', '给票数最高的冠军打上【发光:5次】标签')">✨ 颁发发光特权</div>
                </div>
            `;
            document.getElementById('popup-body').innerHTML = html;
            document.getElementById('overlay').style.display = 'flex';
        }

        // 把原本放在底部的“库存”按钮塞进了“监控”面板的最上面，不占位置
        function openMembers() {
            document.getElementById('popup-title').innerText = "群成员监控";
            let html = `
                <div style="margin-bottom:10px; text-align:right;">
                    <button class="list-item-btn green" onclick="openInventory()">📦 查看我的库存道具</button>
                </div>
            `;
            globalData.members.forEach(mem => {
                let badge = mem.status.includes('禁言') ? `<span class="status-badge status-banned">封印</span>` : (mem.status.includes('发光') ? `<span class="status-badge status-glow">群宠✨</span>` : '');
                html += `
                    <div class="list-item">
                        <div style="font-size:13px; font-weight:bold;">${mem.name} ${badge}</div>
                        <div class="btn-group">
                            <button class="list-item-btn blue" onclick="handleClick('查看私聊', '${mem.name}')">私聊</button>
                            <button class="list-item-btn" onclick="handleClick('系统惩罚', '禁言 ${mem.name}')">禁言</button>
                        </div>
                    </div>`;
            });
            document.getElementById('popup-body').innerHTML = html;
            document.getElementById('overlay').style.display = 'flex';
        }

        function openInventory() {
            document.getElementById('popup-title').innerText = "📦 上帝行囊 (库存)";
            let html = '';
            globalData.inventory.forEach(inv => {
                html += `
                    <div class="list-item">
                        <div>
                            <div style="font-weight:bold; font-size:13px;">${inv.name}</div>
                            <div style="font-size:11px; color:#aaa;">剩余: x${inv.count}</div>
                        </div>
                        <button class="list-item-btn blue" onclick="handleClick('群主使用道具', '${inv.name}')">使用</button>
                    </div>`;
            });
            if(globalData.inventory.length === 0) html = "<div style='text-align:center; color:#888;'>库存为空</div>";
            document.getElementById('popup-body').innerHTML = html;
            document.getElementById('overlay').style.display = 'flex';
        }

        // 全局快捷指令（原底部的“更多”）
        function openGroupActions() {
            document.getElementById('popup-title').innerText = "⚙️ 更多群主指令";
            let html = `
                <div class="action-section-title">🎲 活跃气氛</div>
                <div class="action-grid">
                    <div class="action-btn" onclick="handleClick('发送群公告', '要求全员爆照')">要求全员爆照</div>
                    <div class="action-btn" onclick="handleClick('系统指令', '解除全员禁言')">大赦天下</div>
                    <div class="action-btn" onclick="handleClick('发送系统提示', '查岗')">全员查岗</div>
                </div>
            `;
            document.getElementById('popup-body').innerHTML = html;
            document.getElementById('overlay').style.display = 'flex';
        }

        function openPrivateActions() {
            let target = globalData.privateChat.targetName;
            document.getElementById('popup-title').innerText = `对 [${target}] 的专属操作`;
            let html = `
