        .avatar.banned { filter: grayscale(100%) brightness(0.6); border-color: #333;}
        .avatar.banned::after { content: "⛓️"; position: absolute; font-size: 24px; top: 50%; left: 50%; transform: translate(-50%, -50%); opacity: 0.9; }

        .msg-content-wrapper { display: flex; flex-direction: column; max-width: 75%; position: relative; }
        .msg-name { font-size: 11px; color: rgba(255,255,255,0.8); margin-bottom: 4px; text-shadow: 0 1px 2px rgba(0,0,0,0.5); font-weight: 600;}

        /* 增加了 user-select:none 防止双击选中文本，让双击发光更顺畅 */
        .msg-bubble {
            background: rgba(255, 255, 255, 0.95); padding: 12px 16px; border-radius: 4px 18px 18px 18px; font-size: 14px; color: #333;
            line-height: 1.5; word-wrap: break-word; box-shadow: 0 5px 15px rgba(0,0,0,0.1); position: relative; cursor: pointer; user-select: none;
            transition: all 0.3s;
        }

        /* 发光 Buff 效果 */
        .glow-bubble {
            background: #fff; border: 2px solid #ffeb3b;
            box-shadow: 0 0 20px rgba(255, 235, 59, 0.6), inset 0 0 10px rgba(255,235,59,0.3) !important;
            animation: pulse-glow 1.5s infinite alternate;
        }
        @keyframes pulse-glow { 0% { box-shadow: 0 0 10px rgba(255,235,59,0.5); } 100% { box-shadow: 0 0 30px rgba(255,235,59,1); } }

        .msg-right { flex-direction: row-reverse; }
        .msg-right .msg-content-wrapper { align-items: flex-end; }
        .msg-right .msg-bubble { background: linear-gradient(135deg, #00f2fe, #4facfe); border-radius: 18px 4px 18px 18px; color: #fff; box-shadow: 0 5px 15px rgba(0,242,254,0.3); text-shadow: 0 1px 1px rgba(0,0,0,0.1);}
        .msg-right .avatar::before { content: "👑"; position: absolute; top: -16px; left: 50%; transform: translateX(-50%); font-size: 20px; filter: drop-shadow(0 2px 4px rgba(0,0,0,0.5)); }

        .shake-effect { animation: shake 0.5s cubic-bezier(.36,.07,.19,.97) both; }
        @keyframes shake { 10%, 90% { transform: translate3d(-2px, 0, 0); } 20%, 80% { transform: translate3d(3px, 0, 0); } 30%, 50%, 70% { transform: translate3d(-5px, 0, 0); } 40%, 60% { transform: translate3d(5px, 0, 0); } }
        .red-packet { position: absolute; pointer-events: none; z-index: 100; animation: fall linear forwards; font-size: 24px; filter: drop-shadow(0 5px 5px rgba(0,0,0,0.3));}
        @keyframes fall { to { transform: translateY(800px) rotate(360deg); opacity: 0; } }

        .bottom-area { background: rgba(255, 255, 255, 0.2); border-top: 1px solid rgba(255,255,255,0.4); backdrop-filter: blur(10px); }
        .toolbar { display: flex; justify-content: space-around; padding: 10px 5px; border-bottom: 1px solid rgba(255,255,255,0.2); }
        .tool-btn {
            display: flex; align-items: center; gap: 4px; font-size: 12px; font-weight: bold; color: #fff; cursor: pointer;
            padding: 8px 12px; border-radius: 14px; background: rgba(0,0,0,0.15); border: 1px solid rgba(255,255,255,0.3);
            transition: all 0.2s; box-shadow: 0 2px 5px rgba(0,0,0,0.1); text-shadow: 0 1px 2px rgba(0,0,0,0.3);
        }
        .tool-btn:hover { background: rgba(255, 255, 255, 0.3); transform: translateY(-2px); box-shadow: 0 5px 15px rgba(0,0,0,0.2);}

        .input-bar { padding: 12px 15px; display: flex; align-items: center; gap: 10px; }
        .real-input {
            flex: 1; height: 44px; background: rgba(255,255,255,0.9); border-radius: 22px;
            padding: 0 18px; color: #333; font-size: 14px; border: 2px solid transparent;
            outline: none; transition: all 0.2s; box-shadow: inset 0 2px 5px rgba(0,0,0,0.1);
        }
        .real-input:focus { border-color: #00f2fe; box-shadow: 0 0 15px rgba(0,242,254,0.4); }
        .real-input::placeholder { color: #999; }

        .send-btn {
            width: 44px; height: 44px; border-radius: 50%; background: linear-gradient(135deg, #00f2fe, #4facfe); color: #fff;
            display: flex; justify-content: center; align-items: center; font-size: 20px; font-weight: bold;
            cursor: pointer; box-shadow: 0 4px 15px rgba(0,242,254,0.4); transition: transform 0.2s; border: none; outline: none;
        }
        .send-btn:hover { transform: scale(1.1); box-shadow: 0 6px 20px rgba(0,242,254,0.6); }

        .overlay { position: absolute; top: 0; left: 0; right: 0; bottom: 0; background: rgba(0,0,0,0.4); backdrop-filter: blur(5px); z-index: 50; display: none; justify-content: center; align-items: center; }
        .popup-panel { background: rgba(255, 255, 255, 0.95); width: 90%; max-height: 80%; border-radius: 24px; display: flex; flex-direction: column; box-shadow: 0 30px 60px rgba(0,0,0,0.3); color: #333; overflow: hidden;}
        .popup-header { background: linear-gradient(90deg, #f64f59, #c471ed); color: white; padding: 18px 20px; display: flex; justify-content: space-between; font-weight: 800; font-size: 16px; text-shadow: 0 2px 4px rgba(0,0,0,0.2);}
        .close-btn { cursor: pointer; color: #fff; font-size: 20px; transition: transform 0.2s;}
        .close-btn:hover { transform: rotate(90deg); }
        .popup-content { padding: 20px; overflow-y: auto; display: flex; flex-direction: column; gap: 12px; background: #f9f9f9;}

        .list-item { display: flex; justify-content: space-between; align-items: center; padding: 12px 15px; background: #fff; border-radius: 12px; box-shadow: 0 2px 8px rgba(0,0,0,0.05); border: 1px solid #eee;}
        .btn-group { display: flex; gap: 8px; }
        .list-item-btn { background: #ff4757; color: white; border: none; padding: 8px 12px; border-radius: 8px; font-size: 12px; font-weight:bold; cursor: pointer; transition: opacity 0.2s;}
        .list-item-btn:hover { opacity: 0.8;}
        .list-item-btn.blue { background: #00f2fe; color: #fff; box-shadow: 0 2px 5px rgba(0,242,254,0.3);}
        .list-item-btn.green { background: #2ed573; color: #fff;}

        .action-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
        .action-btn { background: #fff; border: 1px solid #e0e0e0; color: #333; padding: 14px; border-radius: 12px; text-align: center; font-weight:600; cursor: pointer; transition: all 0.2s; font-size: 13px; box-shadow: 0 2px 5px rgba(0,0,0,0.02);}
        .action-btn:hover { background: #f0fbff; border-color: #00f2fe; color: #00f2fe; transform: translateY(-2px); box-shadow: 0 5px 15px rgba(0,242,254,0.15);}
        .action-section-title { font-size: 13px; color: #666; margin-top: 10px; margin-bottom: 5px; font-weight: bold; border-left: 3px solid; padding-left: 8px;}

        .private-drawer {
            position: absolute; top: 0; left: 0; right: 0; bottom: 0; background: rgba(245, 247, 250, 0.98); z-index: 40;
            display: flex; flex-direction: column; transform: translateX(100%); transition: transform 0.4s cubic-bezier(0.19, 1, 0.22, 1);
        }
        .private-drawer.open { transform: translateX(0); }
        .drawer-top { background: linear-gradient(90deg, #12c2e9, #c471ed); color: #fff; padding: 18px 15px; display: flex; justify-content: space-between; align-items: center; box-shadow: 0 4px 10px rgba(0,0,0,0.1); }
        .drawer-back { font-size: 16px; cursor: pointer; font-weight: bold; display: flex; align-items: center; text-shadow: 0 1px 2px rgba(0,0,0,0.2);}
        .drawer-title { font-size: 17px; font-weight: 800; text-shadow: 0 1px 2px rgba(0,0,0,0.2);}
        .drawer-chat { flex: 1; padding: 15px; overflow-y: auto; display: flex; flex-direction: column; gap: 15px; background: url('data:image/svg+xml;utf8,<svg opacity="0.05" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100"><circle cx="50" cy="50" r="40" stroke="%23333" stroke-width="2" fill="none"/></svg>') center/cover; }
        .drawer-bottom { background: #fff; border-top: 1px solid #eee; padding: 12px 15px; display: flex; align-items: center; gap: 12px; box-shadow: 0 -5px 15px rgba(0,0,0,0.03);}
        .pm-icon { font-size: 20px; cursor: pointer; color: #4facfe; transition: transform 0.2s; display: flex; justify-content: center; align-items: center; width: 40px; height: 40px; border-radius: 50%; background: #f0fbff; border: 1px solid #ddf6ff;}
        .pm-icon:hover { transform: scale(1.1); background: #4facfe; color: #fff; }

        .status-badge { font-size: 11px; padding: 2px 8px; border-radius: 10px; margin-left: 6px; font-weight: 800; }
        .status-normal { background: rgba(0, 242, 254, 0.1); color: #008eb3; }
        .status-banned { background: rgba(255, 71, 87, 0.1); color: #ff4757; border: 1px solid #ff4757;}
        .status-glow { background: rgba(255, 235, 59, 0.2); color: #d4a000; border: 1px solid #ffeb3b;}
    </style>
</head>
<body>
    <div class="phone-container" id="content"></div>

    <script>
        const exampleXML = `<group_chat_admin>$1</group_chat_admin>`;
        let globalData = null;
        let memberStatusMap = {};

        function getAvatarColor(name) {
            const colors = ['#ff6b81', '#ff7f50', '#ffa502', '#2ed573', '#1e90ff', '#3742fa', '#5352ed', '#a4b0be'];
            let hash = 0; for(let i = 0; i < name.length; i++) hash = name.charCodeAt(i) + ((hash << 5) - hash);
            return colors[Math.abs(hash) % colors.length];
        }

        function parseXML(xmlText) {
            const data = {
                system: { notice: "暂无公告" }, event: { name: "", rules: "", type: "普通", ranks: [] },
                messages: [], inventory: [], members: [], privateChat: { targetName: "无", status: "正常", pmList: [] }
            };
            try {
                const sysMatch = xmlText.match(/<system_info>([\s\S]*?)<\/system_info>/i);
                if (sysMatch) { const n = sysMatch[1].match(/\[群公告\|([^\]]+)\]/); if(n) data.system.notice = n[1]; }
                const evtMatch = xmlText.match(/<current_event>([\s\S]*?)<\/current_event>/i);
                if (evtMatch) {
                    const t = evtMatch[1];
                    const nMatch = t.match(/\[活动名称\|([^\]]+)\]/); if(nMatch) data.event.name = nMatch[1];
                    const rMatch = t.match(/\[活动规则\|([^\]]+)\]/); if(rMatch) data.event.rules = rMatch[1];
                    const rankMatch = t.match(/\[实时排名\|([^\]]+)\]/);
                    if(rankMatch && !rankMatch[1].includes('无')){ rankMatch[1].split('|').forEach(p => { const [k,v] = p.split(':'); if(k&&v) data.event.ranks.push({name:k,score:v}); }); }
                }
                const invMatch = xmlText.match(/<admin_inventory>([\s\S]*?)<\/admin_inventory>/i);
                if (invMatch) {
                    const regex = /\[道具\|([^\|]+)\|([^\]]+)\]/g; let m;
                    while ((m = regex.exec(invMatch[1])) !== null) { if(m[1] !== '无') data.inventory.push({ name: m[1], count: m[2] }); }
                }
                const memMatch = xmlText.match(/<members>([\s\S]*?)<\/members>/i);
                if (memMatch) {
                    const regex = /\[成员\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g; let m;
                    while ((m = regex.exec(memMatch[1])) !== null) {
                        if(m[1] !== '无') { data.members.push({ name: m[1], status: m[2], points: m[3] }); memberStatusMap[m[1]] = m[2]; }
                    }
                }
                const msgMatch = xmlText.match(/<messages>([\s\S]*?)<\/messages>/i);
                if (msgMatch) {
                    const regex = /\[消息\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g; let m;
                    while ((m = regex.exec(msgMatch[1])) !== null) { data.messages.push({ author: m[2], content: m[3], time: m[6] }); }
                }
                const pmMatch = xmlText.match(/<private_chat>([\s\S]*?)<\/private_chat>/i);
                if (pmMatch) {
                    const t = pmMatch[1].match(/\[私聊对象\|([^\]]+)\]/); if(t) data.privateChat.targetName = t[1];
                    const s = pmMatch[1].match(/\[对象状态\|([^\]]+)\]/); if(s) data.privateChat.status = s[1];
                    const pmRegex = /\[私聊消息\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g; let m;
                    while ((m = pmRegex.exec(pmMatch[1])) !== null) { data.privateChat.pmList.push({ sender: m[1], content: m[2], time: m[3] }); }
                }
            } catch (e) { console.error(e); }
            return data;
        }

        function triggerShake() {
            const container = document.querySelector('.phone-container');
            container.classList.add('shake-effect'); setTimeout(() => container.classList.remove('shake-effect'), 500);
        }

        function createRedPacketRain() {
            const container = document.querySelector('.phone-container');
            for(let i=0; i<15; i++){
                let rp = document.createElement('div'); rp.className = 'red-packet'; rp.innerText = '🧧';
                rp.style.left = Math.random() * 90 + '%'; rp.style.top = '-30px';
                rp.style.animationDuration = (Math.random() * 1 + 1) + 's'; rp.style.animationDelay = (Math.random() * 0.5) + 's';
                container.appendChild(rp); setTimeout(() => rp.remove(), 2000);
            }
        }

        function sendActualMessage(inputId) {
            const inputEl = document.getElementById(inputId);
            if(!inputEl) return;
            const text = inputEl.value.trim();
            if(!text) return;
            try {
                const stTextarea = document.getElementById('send_textarea');
                const stSendBtn = document.getElementById('send_but');
                if (stTextarea && stSendBtn) {
                    stTextarea.value = text;
                    stTextarea.dispatchEvent(new Event('input', { bubbles: true }));
                    stSendBtn.click();
                    inputEl.value = '';
                    return;
                }
            } catch(e) { console.log(e); }
            if (typeof triggerSlash === 'function') { triggerSlash(text); inputEl.value = ''; }
            else { alert(`模拟发送：${text}`); }
        }

        function handleEnterKey(event, inputId) {
            if (event.key === 'Enter') { event.preventDefault(); sendActualMessage(inputId); }
        }

        function render(data) {
            globalData = data;
            let needShake = false; let needRain = false;
            data.messages.forEach(msg => {
                if(msg.content.includes('💥') || msg.content.includes('🔥')) needShake = true;
                if(msg.content.includes('🧧')) needRain = true;
            });

            let html = `
                <div class="top-bar"><div class="group-title">💠 万界交互域 (${data.members.length})</div></div>
                <div class="pinned-area"><div><span class="notice-tag">📢 谕旨:</span> ${data.system.notice}</div>
            `;
            if(data.event.ranks.length > 0 || data.event.name !== "无"){
                html += `
                <div class="event-card">
                    <div class="event-title">🎯 ${data.event.name || '当前盛典'}</div>
                    <div class="event-rules">规则: ${data.event.rules || '无'}</div>
                    <div class="rank-list">`;
                data.event.ranks.forEach(r => { html += `<div class="rank-badge">${r.name}: ${r.score}票</div>`; });
                html += `</div></div>`;
            }
            html += `</div><div class="chat-area" id="chat-area">`;

            data.messages.forEach(msg => {
                let initial = msg.author.charAt(0); let bgColor = getAvatarColor(msg.author);
                let status = memberStatusMap[msg.author] || "正常";
                let avatarClass = status.includes("禁言") ? "avatar banned" : "avatar";
                let bubbleClass = status.includes("发光") ? "msg-bubble glow-bubble" : "msg-bubble";

                // 【特权彩蛋】：加了 ondblclick="this.classList.toggle('glow-bubble')"
                html += `
                    <div class="message-row">
                        <div class="${avatarClass}" style="background:${status.includes('禁言')?'#eee':bgColor}" onclick="handleClick('拍一拍', '${msg.author}')">${initial}</div>
                        <div class="msg-content-wrapper">
                            <div class="msg-name">${msg.author}</div>
                            <div class="${bubbleClass}" ondblclick="this.classList.toggle('glow-bubble')" title="双击立刻让该气泡发光">${msg.content}</div>
                        </div>
                    </div>`;
            });
            html += `</div>`;

            html += `
                <div class="bottom-area">
                    <div class="toolbar">
                        <div class="tool-btn" onclick="openMembers()">👥 监察</div>
                        <div class="tool-btn" onclick="openQuickPM()" style="border-color:#ff4757; color:#ff4757;">💬 翻牌</div>
                        <div class="tool-btn" onclick="openEventCenter()" style="border-color:#00f2fe; color:#008eb3;">🏆 赛事</div>
                        <div class="tool-btn" onclick="openGroupActions()">⚙️ 敕令</div>
                    </div>
                    <div class="input-bar">
                        <input type="text" class="real-input" id="group-real-input" placeholder="降下神谕..." onkeypress="handleEnterKey(event, 'group-real-input')">
                        <button class="send-btn" title="发送" onclick="sendActualMessage('group-real-input')">➤</button>
                    </div>
                </div>
            `;

            html += `
                <div class="overlay" id="overlay" onclick="closePopup(event)">
                    <div class="popup-panel" id="popup-panel">
                        <div class="popup-header"><span id="popup-title">管理枢纽</span><span class="close-btn" onclick="closePopup()">✖</span></div>
                        <div class="popup-content" id="popup-body"></div>
                    </div>
                </div>
            `;

            html += `
                <div class="private-drawer" id="private-drawer">
                    <div class="drawer-top">
                        <div class="drawer-back" onclick="closePrivateDrawer()">❮ 收纳</div>
                        <div class="drawer-title" id="drawer-title">未知</div>
                        <div class="pm-icon" onclick="openPrivateActions()" style="width:32px; height:32px; font-size: 16px; background:rgba(255,255,255,0.2); border:none; color:white;">⚙️</div>
                    </div>
                    <div class="drawer-chat" id="drawer-chat"></div>
                    <div class="drawer-bottom">
                        <input type="text" class="real-input" id="pm-real-input" placeholder="私密传音..." onkeypress="handleEnterKey(event, 'pm-real-input')" style="height:40px;">
                        <button class="send-btn" style="width:40px; height:40px; font-size:16px;" onclick="sendActualMessage('pm-real-input')">➤</button>
                        <div class="pm-icon" title="降临现世(线下)" onclick="handleClick('使用神念降临协议发起线下约会', '${data.privateChat.targetName}')">🏨</div>
                    </div>
                </div>
            `;

            document.getElementById('content').innerHTML = html;

            if (data.privateChat.targetName !== '无') {
                let pmData = data.privateChat;
                let statusClass = pmData.status.includes('禁言') ? 'status-banned' : (pmData.status.includes('发光') ? 'status-glow' : 'status-normal');
                document.getElementById('drawer-title').innerHTML = `${pmData.targetName} <span class="status-badge ${statusClass}">${pmData.status}</span>`;
                let pmHtml = ''; let targetColor = getAvatarColor(pmData.targetName); let targetInitial = pmData.targetName.charAt(0);
                pmData.pmList.forEach(msg => {
                    // 私聊气泡也加上了双击发光后门哦
                    if (msg.sender === '群主') {
                        pmHtml += `<div class="message-row msg-right" style="margin-bottom:10px;"><div class="avatar" style="background:#222; border-color:#fff;">R</div><div class="msg-content-wrapper"><div class="msg-bubble" ondblclick="this.classList.toggle('glow-bubble')" title="双击发光">${msg.content}</div></div></div>`;
                    } else {
                        pmHtml += `<div class="message-row msg-left" style="margin-bottom:10px;"><div class="avatar" style="background:${targetColor}">${targetInitial}</div><div class="msg-content-wrapper"><div class="pm-bubble" ondblclick="this.classList.toggle('glow-bubble')" title="双击发光">${msg.content}</div></div></div>`;
                    }
                });
                document.getElementById('drawer-chat').innerHTML = pmHtml;
                document.getElementById('private-drawer').classList.add('open');
            }

            setTimeout(() => {
                const chatArea = document.getElementById('chat-area'); if(chatArea) chatArea.scrollTop = chatArea.scrollHeight;
                const pmArea = document.getElementById('drawer-chat'); if(pmArea) pmArea.scrollTop = pmArea.scrollHeight;
                if(needShake) triggerShake(); if(needRain) createRedPacketRain();
            }, 100);
        }

        function closePopup(e) { if (e && e.target !== document.getElementById('overlay') && !e.target.classList.contains('close-btn')) return; document.getElementById('overlay').style.display = 'none'; }
        function closePrivateDrawer() { document.getElementById('private-drawer').classList.remove('open'); }
        function handleClick(action, param) {
            if (typeof triggerSlash === 'function') triggerSlash(`/send ${action}：${param}|/trigger`);
            else alert(`指令：${action} ${param}`);
            closePopup();
        }

        function openQuickPM() {
            document.getElementById('popup-title').innerText = "💬 私人联络录 (翻牌)";
            let html = `<div style="display:grid; grid-template-columns: 1fr 1fr; gap:10px;">`;
            globalData.members.forEach(mem => {
                let initial = mem.name.charAt(0);
                let bgColor = getAvatarColor(mem.name);
                html += `
                    <div onclick="handleClick('查看私聊', '${mem.name}')" style="background:#fff; border:1px solid #eee; border-radius:12px; padding:10px; display:flex; align-items:center; gap:10px; cursor:pointer; box-shadow:0 2px 5px rgba(0,0,0,0.05); transition:all 0.2s;" onmouseover="this.style.transform='scale(1.05)';this.style.borderColor='#ff4757';" onmouseout="this.style.transform='scale(1)';this.style.borderColor='#eee';">
                        <div style="width:36px; height:36px; border-radius:10px; background:${bgColor}; color:#fff; display:flex; justify-content:center; align-items:center; font-weight:bold; font-size:14px; flex-shrink:0;">${initial}</div>
                        <div style="font-size:12px; font-weight:bold; color:#333; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">${mem.name}</div>
                    </div>
                `;
            });
            html += `</div>`;
            document.getElementById('popup-body').innerHTML = html;
            document.getElementById('overlay').style.display = 'flex';
        }

        function sendCustomEvent() {
            const inputEl = document.getElementById('custom-event-input');
            if (inputEl && inputEl.value.trim()) { handleClick('发起新活动', inputEl.value.trim()); inputEl.value = ''; }
        }
        function handleCustomEventKey(event) { if (event.key === 'Enter') { event.preventDefault(); sendCustomEvent(); } }

        function openEventCenter() {
            document.getElementById('popup-title').innerText = "🏆 赛事枢纽";
            let html = `
                <div class="action-section-title" style="border-color:#00f2fe; color:#008eb3;">✍️ 御批新赛事</div>
                <div style="display:flex; gap:10px; margin-bottom:15px;">
                    <input type="text" id="custom-event-input" class="real-input" style="height:40px; font-size:13px; background:#fff; border:1px solid #ccc;" placeholder="输入神谕指定比赛..." onkeypress="handleCustomEventKey(event)">
                    <button class="send-btn" style="width:50px; height:40px; font-size:14px; flex-shrink:0; border-radius:12px;" onclick="sendCustomEvent()">发起</button>
                </div>
