            const data = {
                system: { notice: "暂无公告" }, event: { name: "", rules: "", type: "普通", ranks: [] },
                messages: [], inventory: [], members: [], privateChat: { targetName: "无", status: "正常", pmList: [] }
            };
            try {
                const sysMatch = xmlText.match(/<system_info>([\s\S]*?)<\/system_info>/i);
                if (sysMatch) { const n = sysMatch[1].match(/\[群公告\|([^\]]+)\]/); if(n) data.system.notice = n[1]; }

                const evtMatch = xmlText.match(/<current_event>([\s\S]*?)<\/current_event>/i);
                if (evtMatch) {
                    const t = evtMatch[1];
                    const nMatch = t.match(/\[活动名称\|([^\]]+)\]/); if(nMatch) data.event.name = nMatch[1];
                    const rMatch = t.match(/\[活动规则\|([^\]]+)\]/); if(rMatch) data.event.rules = rMatch[1];
                    const rankMatch = t.match(/\[实时排名\|([^\]]+)\]/);
                    if(rankMatch && !rankMatch[1].includes('无')){ rankMatch[1].split('|').forEach(p => { const [k,v] = p.split(':'); if(k&&v) data.event.ranks.push({name:k,score:v}); }); }
                }

                const invMatch = xmlText.match(/<admin_inventory>([\s\S]*?)<\/admin_inventory>/i);
                if (invMatch) {
                    const regex = /\[道具\|([^\|]+)\|([^\]]+)\]/g; let m;
                    while ((m = regex.exec(invMatch[1])) !== null) { if(m[1] !== '无') data.inventory.push({ name: m[1], count: m[2] }); }
                }

                const memMatch = xmlText.match(/<members>([\s\S]*?)<\/members>/i);
                if (memMatch) {
                    const regex = /\[成员\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g; let m;
                    while ((m = regex.exec(memMatch[1])) !== null) {
                        if(m[1] !== '无') { data.members.push({ name: m[1], status: m[2], points: m[3] }); memberStatusMap[m[1]] = m[2]; }
                    }
                }

                const msgMatch = xmlText.match(/<messages>([\s\S]*?)<\/messages>/i);
                if (msgMatch) {
                    const regex = /\[消息\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g; let m;
                    while ((m = regex.exec(msgMatch[1])) !== null) { data.messages.push({ author: m[2], content: m[3], time: m[6] }); }
                }

                const pmMatch = xmlText.match(/<private_chat>([\s\S]*?)<\/private_chat>/i);
                if (pmMatch) {
                    const t = pmMatch[1].match(/\[私聊对象\|([^\]]+)\]/); if(t) data.privateChat.targetName = t[1];
                    const s = pmMatch[1].match(/\[对象状态\|([^\]]+)\]/); if(s) data.privateChat.status = s[1];
                    const pmRegex = /\[私聊消息\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g; let m;
                    while ((m = pmRegex.exec(pmMatch[1])) !== null) { data.privateChat.pmList.push({ sender: m[1], content: m[2], time: m[3] }); }
                }
            } catch (e) { console.error(e); }
            return data;
        }

        function triggerShake() {
            const container = document.querySelector('.phone-container');
            container.classList.add('shake-effect'); setTimeout(() => container.classList.remove('shake-effect'), 500);
        }

        function createRedPacketRain() {
            const container = document.querySelector('.phone-container');
            for(let i=0; i<15; i++){
                let rp = document.createElement('div'); rp.className = 'red-packet'; rp.innerText = '🧧';
                rp.style.left = Math.random() * 90 + '%'; rp.style.top = '-30px';
                rp.style.animationDuration = (Math.random() * 1 + 1) + 's'; rp.style.animationDelay = (Math.random() * 0.5) + 's';
                container.appendChild(rp); setTimeout(() => rp.remove(), 2000);
            }
        }

        function sendActualMessage(inputId) {
            const inputEl = document.getElementById(inputId);
            if(!inputEl) return;
            const text = inputEl.value.trim();
            if(!text) return;
            try {
                const stTextarea = document.getElementById('send_textarea');
                const stSendBtn = document.getElementById('send_but');
                if (stTextarea && stSendBtn) {
                    stTextarea.value = text;
                    stTextarea.dispatchEvent(new Event('input', { bubbles: true }));
                    stSendBtn.click();
                    inputEl.value = '';
                    return;
                }
            } catch(e) { console.log(e); }
            if (typeof triggerSlash === 'function') { triggerSlash(text); inputEl.value = ''; }
            else { alert(`尝试劫持底层输入框发送指令：${text}`); }
        }

        function handleEnterKey(event, inputId) {
            if (event.key === 'Enter') { event.preventDefault(); sendActualMessage(inputId); }
        }

        function render(data) {
            globalData = data;
            let needShake = false; let needRain = false;
            data.messages.forEach(msg => {
                if(msg.content.includes('💥') || msg.content.includes('🔥')) needShake = true;
                if(msg.content.includes('🧧')) needRain = true;
            });

            let html = `
                <div class="top-bar"><div class="group-title">💠 万界交互域 (${data.members.length})</div></div>
                <div class="pinned-area"><div><span class="notice-tag">📢 谕旨:</span> ${data.system.notice}</div>
            `;
            if(data.event.ranks.length > 0 || data.event.name !== "无"){
                html += `
                <div class="event-card">
                    <div class="event-title">🎯 ${data.event.name || '当前盛典'}</div>
                    <div class="event-rules">规则: ${data.event.rules || '无'}</div>
                    <div class="rank-list">`;
                data.event.ranks.forEach(r => { html += `<div class="rank-badge">${r.name}: ${r.score}票</div>`; });
                html += `</div></div>`;
            }
            html += `</div><div class="chat-area" id="chat-area">`;

            data.messages.forEach(msg => {
                let initial = msg.author.charAt(0); let bgColor = getAvatarColor(msg.author);
                let status = memberStatusMap[msg.author] || "正常";
                let avatarClass = status.includes("禁言") ? "avatar banned" : "avatar";
                let bubbleClass = status.includes("发光") ? "msg-bubble glow-bubble" : "msg-bubble";

                html += `
                    <div class="message-row">
                        <div class="${avatarClass}" style="background:${status.includes('禁言')?'#eee':bgColor}" onclick="handleClick('拍一拍', '${msg.author}')">${initial}</div>
                        <div class="msg-content-wrapper">
                            <div class="msg-name">${msg.author}</div>
                            <div class="${bubbleClass}" ondblclick="this.classList.toggle('glow-bubble')" title="双击发光点亮">${msg.content}</div>
                        </div>
                    </div>`;
            });
            html += `</div>`;

            // 底栏四大金刚
            html += `
                <div class="bottom-area">
                    <div class="toolbar">
                        <div class="tool-btn" onclick="openMembers()">👥 监察</div>
                        <div class="tool-btn" onclick="openQuickPM()" style="border-color:#ff4757; color:#ff4757;">💬 翻牌</div>
                        <div class="tool-btn" onclick="openEventCenter()" style="border-color:#00f2fe; color:#008eb3;">🏆 赛事</div>
                        <div class="tool-btn" onclick="openGroupActions()">⚙️ 敕令</div>
                    </div>
                    <div class="input-bar">
                        <input type="text" class="real-input" id="group-real-input" placeholder="降下神谕..." onkeypress="handleEnterKey(event, 'group-real-input')">
                        <button class="send-btn" title="发送" onclick="sendActualMessage('group-real-input')">➤</button>
                    </div>
                </div>
            `;

            // 弹窗
            html += `
                <div class="overlay" id="overlay" onclick="closePopup(event)">
                    <div class="popup-panel" id="popup-panel">
                        <div class="popup-header"><span id="popup-title">管理枢纽</span><span class="close-btn" onclick="closePopup()">✖</span></div>
                        <div class="popup-content" id="popup-body"></div>
                    </div>
                </div>
            `;

            // 私聊抽屉 (保留线下约会按钮和齿轮按钮)
            html += `
                <div class="private-drawer" id="private-drawer">
                    <div class="drawer-top">
                        <div class="drawer-back" onclick="closePrivateDrawer()">❮ 收纳</div>
                        <div class="drawer-title" id="drawer-title">未知</div>
                        <div class="pm-icon" onclick="openPrivateActions()" style="width:32px; height:32px; font-size: 16px; background:rgba(255,255,255,0.2); border:none; color:white;">⚙️</div>
                    </div>
                    <div class="drawer-chat" id="drawer-chat"></div>
                    <div class="drawer-bottom">
                        <input type="text" class="real-input" id="pm-real-input" placeholder="私密传音..." onkeypress="handleEnterKey(event, 'pm-real-input')" style="height:40px;">
                        <button class="send-btn" style="width:40px; height:40px; font-size:16px;" onclick="sendActualMessage('pm-real-input')">➤</button>
                        <div class="pm-icon" title="降临现世(线下约会)" onclick="handleClick('使用神念降临协议发起线下约会', '${data.privateChat.targetName}')">🏨</div>
                    </div>
                </div>
            `;

            document.getElementById('content').innerHTML = html;

            if (data.privateChat.targetName !== '无') {
                let pmData = data.privateChat;
                let statusClass = pmData.status.includes('禁言') ? 'status-banned' : (pmData.status.includes('发光') ? 'status-glow' : 'status-normal');
                document.getElementById('drawer-title').innerHTML = `${pmData.targetName} <span class="status-badge ${statusClass}">${pmData.status}</span>`;
                let pmHtml = ''; let targetColor = getAvatarColor(pmData.targetName); let targetInitial = pmData.targetName.charAt(0);
                pmData.pmList.forEach(msg => {
                    if (msg.sender === '群主') {
                        pmHtml += `<div class="message-row msg-right" style="margin-bottom:10px;"><div class="avatar" style="background:#222; border-color:#fff;">R</div><div class="msg-content-wrapper"><div class="msg-bubble" ondblclick="this.classList.toggle('glow-bubble')">${msg.content}</div></div></div>`;
                    } else {
                        pmHtml += `<div class="message-row msg-left" style="margin-bottom:10px;"><div class="avatar" style="background:${targetColor}">${targetInitial}</div><div class="msg-content-wrapper"><div class="pm-bubble" ondblclick="this.classList.toggle('glow-bubble')">${msg.content}</div></div></div>`;
                    }
                });
                document.getElementById('drawer-chat').innerHTML = pmHtml;
                document.getElementById('private-drawer').classList.add('open');
            }

            setTimeout(() => {
                const chatArea = document.getElementById('chat-area'); if(chatArea) chatArea.scrollTop = chatArea.scrollHeight;
                const pmArea = document.getElementById('drawer-chat'); if(pmArea) pmArea.scrollTop = pmArea.scrollHeight;
                if(needShake) triggerShake(); if(needRain) createRedPacketRain();
            }, 100);
        }

        function closePopup(e) { if (e && e.target !== document.getElementById('overlay') && !e.target.classList.contains('close-btn')) return; document.getElementById('overlay').style.display = 'none'; }
        function closePrivateDrawer() { document.getElementById('private-drawer').classList.remove('open'); }
        function handleClick(action, param) {
            if (typeof triggerSlash === 'function') triggerSlash(`/send ${action}：${param}|/trigger`);
            else alert(`触发指令：${action} ${param}`);
            closePopup();
        }

        // ============ 所有交互面版 ============
        // 翻牌私联录
        function openQuickPM() {
            document.getElementById('popup-title').innerText = "💬 私人联络录 (翻牌)";
            let html = `<div style="display:grid; grid-template-columns: 1fr 1fr; gap:10px;">`;
            globalData.members.forEach(mem => {
                let initial = mem.name.charAt(0); let bgColor = getAvatarColor(mem.name);
                html += `
                    <div onclick="handleClick('查看私聊', '${mem.name}')" style="background:#fff; border:1px solid #eee; border-radius:12px; padding:10px; display:flex; align-items:center; gap:10px; cursor:pointer; box-shadow:0 2px 5px rgba(0,0,0,0.05); transition:all 0.2s;" onmouseover="this.style.transform='scale(1.05)';this.style.borderColor='#ff4757';" onmouseout="this.style.transform='scale(1)';this.style.borderColor='#eee';">
                        <div style="width:36px; height:36px; border-radius:10px; background:${bgColor}; color:#fff; display:flex; justify-content:center; align-items:center; font-weight:bold; font-size:14px; flex-shrink:0;">${initial}</div>
                        <div style="font-size:12px; font-weight:bold; color:#333; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">${mem.name}</div>
                    </div>
                `;
            });
            html += `</div>`;
            document.getElementById('popup-body').innerHTML = html;
            document.getElementById('overlay').style.display = 'flex';
        }

        function sendCustomEvent() {
            const inputEl = document.getElementById('custom-event-input');
            if (inputEl && inputEl.value.trim()) { handleClick('发起新活动', inputEl.value.trim()); inputEl.value = ''; }
        }
        function handleCustomEventKey(event) { if (event.key === 'Enter') { event.preventDefault(); sendCustomEvent(); } }

        // 赛事枢纽（带自定义输入）
        function openEventCenter() {
            document.getElementById('popup-title').innerText = "🏆 赛事枢纽";
            let html = `
                <div class="action-section-title" style="border-color:#00f2fe; color:#008eb3;">✍️ 御批新赛事</div>
                <div style="display:flex; gap:10px; margin-bottom:15px;">
                    <input type="text" id="custom-event-input" class="real-input" style="height:40px; font-size:13px; background:#fff; border:1px solid #ccc;" placeholder="输入神谕指定比赛..." onkeypress="handleCustomEventKey(event)">
                    <button class="send-btn" style="width:50px; height:40px; font-size:14px; flex-shrink:0; border-radius:12px;" onclick="sendCustomEvent()">发起</button>
                </div>
                <div class="action-section-title" style="border-color:#ffeb3b; color:#d4a000;">👑 裁判特权</div>
