                    <div class="action-btn" onclick="handleClick('赛事管理', '立刻结算当前活动并公布结果')">✅ 立刻结算</div>
                </div>
            `;
            document.getElementById('popup-body').innerHTML = html;
            document.getElementById('overlay').style.display = 'flex';
        }

        // 成员监控（内嵌查看库存）
        function openMembers() {
            document.getElementById('popup-title').innerText = "👁️ 群员监察";
            let html = `
                <div style="margin-bottom:10px; text-align:right;">
                    <button class="list-item-btn green" onclick="openInventory()">📦 查阅行囊</button>
                </div>
            `;
            globalData.members.forEach(mem => {
                let badge = mem.status.includes('禁言') ? `<span class="status-badge status-banned">封印</span>` : (mem.status.includes('发光') ? `<span class="status-badge status-glow">受宠✨</span>` : '');
                html += `
                    <div class="list-item">
                        <div style="font-size:13px; font-weight:bold; display:flex; align-items:center; gap:5px;">
                            <span style="display:inline-block; max-width:120px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">${mem.name}</span>
                            ${badge}
                        </div>
                        <div class="btn-group">
                            <button class="list-item-btn" onclick="handleClick('系统惩罚', '禁言 ${mem.name}')">⛓️ 封禁</button>
                        </div>
                    </div>`;
            });
            document.getElementById('popup-body').innerHTML = html;
            document.getElementById('overlay').style.display = 'flex';
        }

        // 查看库存
        function openInventory() {
            document.getElementById('popup-title').innerText = "📦 上帝行囊";
            let html = '';
            globalData.inventory.forEach(inv => {
                html += `
                    <div class="list-item">
                        <div>
                            <div style="font-weight:bold; font-size:13px; color:#333;">${inv.name}</div>
                            <div style="font-size:11px; color:#666;">剩余数量: x${inv.count}</div>
                        </div>
                        <button class="list-item-btn blue" onclick="handleClick('群主使用道具', '${inv.name}')">降下</button>
                    </div>`;
            });
            if(globalData.inventory.length === 0) html = "<div style='text-align:center; color:#999; padding:20px;'>行囊空空如也</div>";
            document.getElementById('popup-body').innerHTML = html;
            document.getElementById('overlay').style.display = 'flex';
        }

        // 更多指令
        function openGroupActions() {
            document.getElementById('popup-title').innerText = "⚙️ 敕令中心";
            let html = `
                <div class="action-grid">
                    <div class="action-btn" onclick="handleClick('发送群公告', '要求全员爆照')">📸 勒令爆照</div>
                    <div class="action-btn" onclick="handleClick('群主发红包', '拼手气红包')">🧧 撒发功德</div>
                    <div class="action-btn" onclick="handleClick('发送系统提示', '查岗')">👀 全员查岗</div>
                    <div class="action-btn" style="border-color:#2ed573; color:#2ed573;" onclick="handleClick('系统指令', '解除全员禁言')">🕊️ 大赦天下</div>
                </div>
            `;
            document.getElementById('popup-body').innerHTML = html;
            document.getElementById('overlay').style.display = 'flex';
        }

        // 私聊惩罚指令
        function openPrivateActions() {
            let target = globalData.privateChat.targetName;
            document.getElementById('popup-title').innerText = `💕 拿捏 [${target}]`;
            let html = `
                <div class="action-grid">
                    <div class="action-btn" onclick="handleClick('对 ${target} 使用调情指令', '强制摸头')">🤚 强制摸头</div>
                    <div class="action-btn" onclick="handleClick('对 ${target} 使用调情指令', '要求发语音撒娇')">🎙️ 勒令撒娇</div>
                    <div class="action-btn" onclick="handleClick('对 ${target} 使用惩罚指令', '没收一件衣物')">👗 剥夺衣物</div>
                    <div class="action-btn" onclick="handleClick('对 ${target} 使用调情指令', '强制命令其叫主人')">🛐 跪称主人</div>
                </div>
            `;
            document.getElementById('popup-body').innerHTML = html;
            document.getElementById('overlay').style.display = 'flex';
        }

        document.addEventListener('DOMContentLoaded', () => { render(parseXML(exampleXML)); });
    </script>
</body>
</html>
