        const exampleXML = `<group_chat_admin>$1</group_chat_admin>`;

        function parseXML(xml) {
            console.log("青子开始解析XML啦...", xml.substring(0, 100));
            const data = { notice: '', messages: [], private: null };

            try {
                const sysMatch = xml.match(/<system_info>([\s\S]*?)<\/system_info>/);
                if(sysMatch) {
                    const noticeMatch = sysMatch[1].match(/\[群公告\|([^\]]+)\]/);
                    if(noticeMatch) data.notice = noticeMatch[1];
