                            id: m[1], name: m[2], content: m[3], time: m[6]
                        });
                    }
                }

                const privMatch = xml.match(/<private_chat>([\s\S]*?)<\/private_chat>/);
                if(privMatch) {
                    const targetMatch = privMatch[1].match(/\[私聊对象\|([^\]]+)\]/);
                    const target = targetMatch ? targetMatch[1] : '无';

                    if(target !== '无') {
                        data.private = { target: target, messages: [] };
                        const regex = /\[私聊消息\|([^|]+)\|([^|]+)\|([^\]]+)\]/g;
                        let m;
                        while((m = regex.exec(privMatch[1])) !== null) {
                            data.private.messages.push({
                                sender: m[1], content: m[2], time: m[3]
                            });
                        }
                    }
                }
                return data;
            } catch (err) {
                console.error("解析爆炸啦！", err);
                return data;
            }
        }

        // ================= 强力劫持核心 =================
        function triggerRealSend(text) {
            if (!text.trim()) return;
            console.log("准备发送指令:", text);

            try {
                // 方案1: 尝试触发 ST 的原生指令接口 (最稳定)
                if (typeof triggerSlash === 'function') {
                    console.log("使用 triggerSlash 发送");
                    triggerSlash(`/send ${text}|/trigger`);
                    return;
                }

                // 方案2: 强力突破 DOM (绕过框架限制)
                const realTextarea = document.getElementById('send_textarea');
                const realSendBtn = document.getElementById('send_but');

                if (realTextarea && realSendBtn) {
                    console.log("找到原生输入框，强行注入!");

                    // 强行修改底层 value，防止框架拦截
                    const nativeInputValueSetter = Object.getOwnPropertyDescriptor(window.HTMLTextAreaElement.prototype, "value").set;
                    nativeInputValueSetter.call(realTextarea, text);

                    // 派发多个事件骗过框架
                    realTextarea.dispatchEvent(new Event('input', { bubbles: true }));
                    realTextarea.dispatchEvent(new Event('change', { bubbles: true }));

                    // 延迟10毫秒点击，给框架反应时间
                    setTimeout(() => {
                        realSendBtn.click();
                        console.log("发送按钮点击完成!");
                    }, 10);
                } else {
                    alert("报告哥哥，找不到原生输入框！是不是ST换皮肤了？");
                }
            } catch (err) {
                console.error("发送函数崩溃:", err);
                alert("发送时发生错误: " + err.message);
            }
        }

        function handleFakeInputKeydown(e) {
            if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                const input = e.target;
                triggerRealSend(input.value);
                input.value = '';
            }
        }

        function handleSendBtnClick() {
            const input = document.getElementById('fake-chat-input');
            if(input) {
                triggerRealSend(input.value);
                input.value = '';
            }
        }

        function closeDrawer() {
            document.getElementById('privDrawer').classList.remove('open');
        }

        function render(data) {
            let html = '';

            if(data.notice) html += `<div class="system-notice">${data.notice}</div>`;

            html += `<div class="message-area">`;
            data.messages.forEach(msg => {
                html += `
                    <div class="msg-bubble">
                        <div class="msg-header">
                            <span class="msg-name">${msg.name}</span>
                            <span class="msg-time">${msg.time}</span>
                        </div>
                        <div class="msg-content">${msg.content}</div>
                    </div>
                `;
            });
            html += `</div>`;

            html += `
                <div class="private-drawer ${data.private ? 'open' : ''}" id="privDrawer">
                    <div class="drawer-header">
                        <span class="drawer-title">💬 ${data.private ? data.private.target : ''}</span>
                        <span class="drawer-close" onclick="closeDrawer()">✖</span>
                    </div>
                    <div class="drawer-body">
            `;
            if(data.private) {
                data.private.messages.forEach(msg => {
                    const isSelf = msg.sender === '群主' || msg.sender === '群主邵';
                    html += `
                        <div style="text-align: ${isSelf ? 'right' : 'left'}">
                            <div style="display:inline-block; padding:8px 12px; border-radius:10px; background:${isSelf ? 'rgba(0,255,255,0.2)' : 'rgba(255,0,255,0.2)'}; max-width:80%; text-align:left;">
                                <div style="font-size:12px; color:#aaa; margin-bottom:4px;">${msg.sender} ${msg.time}</div>
                                <div>${msg.content}</div>
                            </div>
                        </div>
                    `;
                });
            }
            html += `</div></div>`;

            html += `
                <div class="input-dock">
                    <input type="text" id="fake-chat-input" class="chat-input" placeholder="降下神谕... (按回车发送)" onkeydown="handleFakeInputKeydown(event)">
                    <button class="send-btn" onclick="handleSendBtnClick()">发送指令</button>
                </div>
            `;

            document.getElementById('app').innerHTML = html;
            console.log("界面渲染完成！");
        }

        document.addEventListener('DOMContentLoaded', () => {
            try {
                const data = parseXML(exampleXML);
                render(data);
            } catch (err) {
                document.getElementById('app').innerHTML = `<div class="error-log">启动失败: ${err.message}</div>`;
            }
        });
    </script>
</body>
</html>
